        onConnect: (id) => setLocalPlayerId(id),
        onOnlineCount: updateOnlineCount,
        onRoomList: updateRoomList,
        onGameStart: (players, worldChanges, seed) => {
            gameState.isOffline = false;
            if (seed) gameState.worldSeed = seed;
            if (worldChanges) worldChanges.forEach(update => applyWorldUpdate(update));
            startGame(players, gameState.localPlayerId);
            addChatMessage("SYSTEM", `Welcome to Terra Wilds! Seed: ${gameState.worldSeed}`, "#fbbf24", true);
        },
        onState: (serverPlayers, serverTime) => {
            const me = getLocalPlayer();
            const serverMe = serverPlayers[gameState.localPlayerId];

            // Синхронизация времени с сервера
            if (typeof serverTime === 'number') {
                gameState.worldTime = serverTime;
            }

            if (me && serverMe) {
                if (serverMe.inventory) syncInventoryWithServer(serverMe.inventory);
                if (serverMe.stats) {
                    me.stats.hp = serverMe.stats.hp;
                    me.stats.maxHp = serverMe.stats.maxHp;
                    me.stats.hunger = serverMe.stats.hunger;
                    me.stats.xp = serverMe.stats.xp;
                    me.stats.level = serverMe.stats.level;
                    if (Math.abs(me.stats.energy - serverMe.stats.energy) > 5) me.stats.energy = serverMe.stats.energy;
                }
                const dist = Math.sqrt(Math.pow(me.x - serverMe.x, 2) + Math.pow(me.y - serverMe.y, 2));
                if (dist > 150) { me.x = serverMe.x; me.y = serverMe.y; }
                else serverPlayers[gameState.localPlayerId] = me;
            }
            setPlayers(serverPlayers);
        },
        onWorldUpdate: (update) => applyWorldUpdate(update),
        onError: (msg) => alert(`Ошибка: ${msg}`),
        onDebugLog: (msg) => console.error(msg),
        onChatMessage: (data) => addChatMessage(data.nickname, data.text, data.color)
    });

    window.addEventListener('resize', resizeCanvas);
    canvas.addEventListener('wheel', (e) => {
        if (!gameContainer.classList.contains('hidden')) { e.preventDefault(); adjustZoom(e.deltaY); }
    }, { passive: false });

    window.addEventListener('keydown', (e) => {
        const startScreen = document.getElementById('start-screen');
        if (startScreen && startScreen.classList.contains('hidden')) {
            if (!isChatOpen && (e.code === 'Enter' || e.code === 'KeyT')) { e.preventDefault(); toggleChat(true); return; }
            if (e.code === 'Escape') { if (isChatOpen) toggleChat(false); else if (isInventoryOpen) toggleInventory(); return; }
            if (isChatOpen) return;
            if (e.code === 'Tab') { e.preventDefault(); toggleInventory(); }
            if (e.code === 'KeyQ') cycleHotbar(-1);
            if (e.code === 'KeyE') cycleHotbar(1);
            if (e.key >= '1' && e.key <= '9') handleHotbarKey(parseInt(e.key) - 1);
        }
    });

    function resizeCanvas() { 
        const dpr = window.devicePixelRatio || 1;
        canvas.width = window.innerWidth * dpr; canvas.height = window.innerHeight * dpr;
        canvas.style.width = window.innerWidth + 'px'; canvas.style.height = window.innerHeight + 'px';
        const ctx = canvas.getContext('2d');
        if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
    }

    function startGame(initialPlayers: Players, playerId: string) {
        setPlayers(initialPlayers);
        setLocalPlayerId(playerId);
        resetInventory();
        const me = initialPlayers[playerId];
        if (me && me.inventory) syncInventoryWithServer(me.inventory);
        initWorld(me.x, me.y);
        showGameScreen();
        resizeCanvas();
        if (fpsEl) fpsEl.classList.remove('hidden');
        gameLoop();
    }

    function startGameOffline() {
        const pid = 'offline_hero';
        if (!gameState.worldSeed || gameState.worldSeed === 'terrawilds') gameState.worldSeed = Math.floor(Math.random() * 1999999999 - 999999999).toString();
        const player: Player = {
            id: pid, x: 0, y: 0, 
            color: PLAYER_COLORS[Math.floor(Math.random() * PLAYER_COLORS.length)], 
            nickname: "Explorer", direction: 'front',
            inventory: [], equipment: { head: null, body: null, legs: null },
            stats: { hp: 20, maxHp: 20, hunger: 20, maxHunger: 20, mana: 20, maxMana: 20, energy: 20, maxEnergy: 20, xp: 0, maxXp: 100, level: 1 }
        };
        startGame({ [pid]: player }, pid);
        if (gameState.useTestWorld) {
            const debugPanel = document.getElementById('debug-panel');
            if (debugPanel) debugPanel.style.display = 'block';
            addChatMessage("DEV", "ТЕСТОВЫЙ МИР: Бесконечные ресурсы и респавн включены.", "#60a5fa", true);
        } else {
            addChatMessage("AI", "Мир готов! Смена дня и ночи запущена. Загляни в дебаг-меню (/debug) для управления временем!", "#10b981");
        }
    }

    function gameLoop() {
        if (gameContainer.classList.contains('hidden')) return;
        const now = performance.now();
        const delta = now - lastLoop;
        lastLoop = now;

        // Продвижение времени (только в офлайне, в онлайне берем с сервера)
        if (gameState.isOffline && !gameState.isTimePaused) {
            gameState.worldTime = (gameState.worldTime + 5) % 24000;
        }

        const me = getLocalPlayer();
        if (me) {
            if (movement.rotate && now - lastRotateTime > 200) { setPlacementRotation((placementRotation + 1) % 4); lastRotateTime = now; }
            handleInteraction(me);
            updateDoorPhysics(); 
            let canSprint = false; let currentSpeed = BASE_WALK_SPEED; let dx = 0, dy = 0; let newDir: Direction = me.direction;
            if (!isChatOpen) {
                if (me.stats) {
                    if (movement.sprint && me.stats.energy > 0) { canSprint = true; me.stats.energy -= 0.15; }
                    else if (!movement.sprint && me.stats.energy < me.stats.maxEnergy) me.stats.energy += 0.1;
                }
                currentSpeed = (canSprint ? BASE_SPRINT_SPEED : BASE_WALK_SPEED) * gameState.debug.speedMult;
                if (isPositionInWater(me.x, me.y)) currentSpeed *= 0.5;
                if (movement.up) { dy -= currentSpeed; newDir = 'back'; }
                if (movement.down) { dy += currentSpeed; newDir = 'front'; }
                if (movement.left) { dx -= currentSpeed; newDir = 'left'; }
                if (movement.right) { dx += currentSpeed; newDir = 'right'; }
            }
            if (dx !== 0 || dy !== 0) { 
                me.direction = newDir; (window as any).isLocalMoving = true; 
                if (dx !== 0 && canMoveTo(me.x + dx, me.y, 32, 32)) me.x += dx;
                if (dy !== 0 && canMoveTo(me.x, me.y + dy, 32, 32)) me.y += dy;
            } else (window as any).isLocalMoving = false;
            if (!gameState.isOffline) emitMovement({ x: me.x, y: me.y, direction: me.direction, sprint: canSprint });
            if (me.stats && hudEls.hp) {
                hudEls.hp.style.width = `${(me.stats.hp / me.stats.maxHp) * 100}%`;
                hudEls.hunger!.style.width = `${(me.stats.hunger / me.stats.maxHunger) * 100}%`;
                hudEls.mana!.style.width = `${(me.stats.mana / me.stats.maxMana) * 100}%`;
                hudEls.energy!.style.width = `${(me.stats.energy / me.stats.maxEnergy) * 100}%`;
                hudEls.xp!.style.width = `${(me.stats.xp / me.stats.maxXp) * 100}%`;
                hudEls.textHp!.textContent = String(Math.floor(me.stats.hp));
                hudEls.textHunger!.textContent = String(Math.floor(me.stats.hunger));
                hudEls.textEnergy!.textContent = String(Math.floor(me.stats.energy));
                hudEls.level!.textContent = String(me.stats.level);
            }
        }
        renderGame(currentMiningProgress, currentMiningTargetX, currentMiningTargetY, !isChatOpen && movement.sprint && me?.stats && me.stats.energy > 0);
        requestAnimationFrame(gameLoop);
    }
});

// renderer.ts: Отрисовка игрового мира и сущностей
import { TILE_SIZE } from './constants';
import { Player } from './types';
import { gameState } from './state';
import { textures, charSprites, AnimFrame } from './assets';
import { getTileData, isPositionInWater, canPlaceObject, getInteractionType } from './world';
import { getSelectedItem } from './inventory';
import { inputState } from './input';
import { placementRotation } from './interaction'; 

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;
export let cameraZoom = 1.5; 

let camX = 0;
let camY = 0;
let isCameraInitialized = false;

interface FloatingText {
    x: number; y: number; text: string; life: number; maxLife: number; color: string;
}
const floatingTexts: FloatingText[] = [];

export function addFloatingText(x: number, y: number, text: string, color: string = '#ffffff') {
    floatingTexts.push({ x, y, text, life: 60, maxLife: 60, color });
}

export function getCameraZoom() { return cameraZoom; }

export function initRenderer(canvasEl: HTMLCanvasElement) {
    canvas = canvasEl; ctx = canvas.getContext('2d');
    if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
}

export function adjustZoom(deltaY: number) {
    cameraZoom -= deltaY * 0.001;
    if (cameraZoom < 0.8) cameraZoom = 0.8;
    if (cameraZoom > 3.0) cameraZoom = 3.0;
}

function getAnimationFrame(isMoving: boolean, isSprinting: boolean): AnimFrame {
    if (!isMoving) return 0;
    const frameDuration = isSprinting ? 75 : 150;
    const now = Date.now();
    const cycle = Math.floor(now / frameDuration) % 4;
    return (cycle === 3) ? 2 : (cycle as AnimFrame);
}

export function drawCharacterPreview(ctxPreview: CanvasRenderingContext2D, player: Player) {
    const w = ctxPreview.canvas.width; const h = ctxPreview.canvas.height;
    ctxPreview.clearRect(0, 0, w, h); ctxPreview.save(); ctxPreview.translate(w/2, h/2); ctxPreview.scale(1.2, 1.2); ctxPreview.translate(-32, -42); 

    // Выбираем спрайт по цвету игрока
    const baseKey = `base_${player.color}`;
    const baseSprite = (charSprites[baseKey] && charSprites[baseKey][0]) ? charSprites[baseKey][0] : (charSprites['base_#FFFFFF'] ? charSprites['base_#FFFFFF'][0] : charSprites['base'][0]);

    if (baseSprite) ctxPreview.drawImage(baseSprite, 0, 0, 64, 84);

    if (player.equipment.legs && charSprites[player.equipment.legs]) ctxPreview.drawImage(charSprites[player.equipment.legs][0], 0, 0, 64, 84);
    if (player.equipment.body && charSprites[player.equipment.body]) ctxPreview.drawImage(charSprites[player.equipment.body][0], 0, 0, 64, 84);
    if (player.equipment.head && charSprites[player.equipment.head]) ctxPreview.drawImage(charSprites[player.equipment.head][0], 0, 0, 64, 84);
    ctxPreview.restore();
}

function drawPlayer(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean, isMoving: boolean, isSprinting: boolean) {
    const isInWater = isPositionInWater(player.x, player.y);
    const x = player.x; let y = player.y;
    if (isInWater) y += 5 + Math.sin(Date.now() / 400) * 2; 
    const frame = getAnimationFrame(isMoving, isSprinting);
    const dir = player.direction || 'front';
    const isFlipped = dir === 'right';
    ctx.save(); ctx.translate(x, y);
    if (!isLocal) {
        ctx.fillStyle = '#FFFFFF'; ctx.shadowColor = 'black'; ctx.shadowBlur = 4; ctx.font = 'bold 12px sans-serif'; ctx.textAlign = 'center'; ctx.fillText(player.nickname, 0, -55); ctx.shadowBlur = 0;
    }
    if (!isInWater) { ctx.fillStyle = 'rgba(0,0,0,0.25)'; ctx.beginPath(); ctx.ellipse(0, 12, 16, 6, 0, 0, Math.PI*2); ctx.fill(); }
    else {
        const ripple = (Math.sin(Date.now() / 500) + 1) / 2;
        ctx.strokeStyle = `rgba(255, 255, 255, ${0.4 - ripple * 0.2})`; ctx.lineWidth = 2; ctx.beginPath(); ctx.ellipse(0, 0, 12 + ripple * 4, 6 + ripple * 2, 0, 0, Math.PI*2); ctx.stroke();
    }
    if (isFlipped) ctx.scale(-1, 1);
    if (isInWater) { ctx.beginPath(); ctx.rect(-40, -100, 80, 100); ctx.clip(); }
    ctx.translate(-32, -60); 

    // Выбираем правильный спрайт базы на основе цвета игрока
    const baseKey = `base_${player.color}`;
    // Fallback: если цвет не найден (например, старый кеш), берем белый
    const baseSpriteSet = charSprites[baseKey] || charSprites['base_#FFFFFF'] || charSprites['base'];

    if (baseSpriteSet && baseSpriteSet[frame]) ctx.drawImage(baseSpriteSet[frame], 0, 0, 64, 84);

    if (player.equipment) {
        if (player.equipment.legs && charSprites[player.equipment.legs]) ctx.drawImage(charSprites[player.equipment.legs][frame], 0, 0, 64, 84);
        if (player.equipment.body && charSprites[player.equipment.body]) ctx.drawImage(charSprites[player.equipment.body][frame], 0, 0, 64, 84);
        if (player.equipment.head && charSprites[player.equipment.head]) ctx.drawImage(charSprites[player.equipment.head][frame], 0, 0, 64, 84);
    }
    if (isLocal) {
        const item = getSelectedItem();
        if (item) {
            ctx.font = '24px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; 

            // Если персонаж развернут, нужно развернуть текст обратно,
            // но при этом скорректировать координату X, так как система координат смещена
            if (isFlipped) {
                ctx.scale(-1, 1);
                // В развернутой системе координат центр спрайта смещается
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, -32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            } else {
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, 32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            }
        }
    }
    ctx.restore();
}

interface RenderObject { y: number; type: string; data: any; }

function lerp(start: number, end: number, t: number) { return start * (1 - t) + end * t; }

export function renderGame(miningProgress: number = 0, targetX: number = 0, targetY: number = 0, isSprinting: boolean = false) {
  if (!ctx || !canvas) return;
  const me = gameState.players[gameState.localPlayerId];
  if (!me) return;
  if (!isCameraInitialized) { camX = me.x; camY = me.y; isCameraInitialized = true; }
  const lerpFactor = isSprinting ? 0.08 : 0.15;
  camX = lerp(camX, me.x, lerpFactor); camY = lerp(camY, me.y, lerpFactor);
  const dpr = window.devicePixelRatio || 1;

  // ФОН: Если тестовый мир - белый/серый, иначе зеленый
  ctx.fillStyle = gameState.useTestWorld ? '#e2e8f0' : '#4e8c33'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  ctx.save();
  ctx.scale(dpr, dpr);
  const logicalWidth = canvas.width / dpr; const logicalHeight = canvas.height / dpr;
  ctx.translate(logicalWidth / 2, logicalHeight / 2);
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-camX, -camY);

  const viewW = logicalWidth / cameraZoom, viewH = logicalHeight / cameraZoom;
  const startTileX = Math.floor((camX - viewW/2) / TILE_SIZE) - 1;
  const endTileX = Math.floor((camX + viewW/2) / TILE_SIZE) + 2;
  const startTileY = Math.floor((camY - viewH/2) / TILE_SIZE) - 2; 
  const endTileY = Math.floor((camY + viewH/2) / TILE_SIZE) + 4;

  const renderList: RenderObject[] = [];

  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const screenX = x * TILE_SIZE, screenY = y * TILE_SIZE;
        const tileData = getTileData(x, y);

        // РЕНДЕРИНГ ПОВЕРХНОСТИ
        if (tileData.terrain === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            // --- ЛОГИКА БЕРЕГОВ (СКРУГЛЕНИЯ) ---
            const isN = getTileData(x, y - 1).terrain === 'grass';
            const isS = getTileData(x, y + 1).terrain === 'grass';
            const isW = getTileData(x - 1, y).terrain === 'grass';
            const isE = getTileData(x + 1, y).terrain === 'grass';

            if (isN && isW) ctx.drawImage(textures['mask_corner_tl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isN && isE) ctx.drawImage(textures['mask_corner_tr'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isW) ctx.drawImage(textures['mask_corner_bl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isE) ctx.drawImage(textures['mask_corner_br'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            const waveHash = Math.sin(x * 12.9898 + y * 78.233) * 43758.5453;
            if ((waveHash - Math.floor(waveHash)) > 0.85) ctx.drawImage(textures['water_wave'], screenX, screenY + Math.sin(Date.now() / 500) * 2, TILE_SIZE, TILE_SIZE);
        } else if (!gameState.useTestWorld) {
            ctx.drawImage(textures['grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.floor === 'wood') ctx.drawImage(textures['floor_wood'], screenX, screenY, TILE_SIZE, TILE_SIZE);

        if (gameState.showDebugGrid || gameState.useTestWorld) {
            ctx.strokeStyle = gameState.useTestWorld ? 'rgba(0,0,0,0.05)' : 'rgba(255,255,255,0.1)'; 
            ctx.strokeRect(screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.object === 'tree') renderList.push({ y: screenY + 35, type: 'tree', data: { x: screenX - 50, y: screenY - 180 } });
        else if (tileData.object === 'stone') renderList.push({ y: screenY + 30, type: 'stone', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'big_rock') renderList.push({ y: screenY + 38, type: 'big_rock', data: { x: screenX - 30, y: screenY - 40 } });
        else if (tileData.object === 'workbench') renderList.push({ y: screenY + 30, type: 'workbench', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'high_grass') ctx.drawImage(textures['high_grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        else if (tileData.object.startsWith('wall_wood') || tileData.object.startsWith('door_wood')) {
             let sortY = screenY + TILE_SIZE; if (tileData.object.includes('_t')) sortY = screenY + 10;
             let angle = 0; if (tileData.object.startsWith('door_wood')) { const k = `${x},${y}`; if (gameState.doorStates[k]) angle = gameState.doorStates[k].angle; }
             renderList.push({ y: sortY, type: tileData.object.startsWith('door_wood') ? 'door' : 'wall', data: { x: screenX, y: screenY, tex: textures[tileData.object], angle, subType: tileData.object.split('_').pop() } });
        }
        tileData.items.forEach((item, i) => {
            const seed = x * 1000 + y + i * 50;
            renderList.push({ y: screenY + TILE_SIZE/2, type: 'ground_item', data: { x: screenX + TILE_SIZE/2 + Math.sin(seed)*10, y: screenY + TILE_SIZE/2 + Math.cos(seed)*10, type: item, rotation: Math.sin(seed*0.1)*Math.PI } });
        });
    }
  }
  for (const id in gameState.players) renderList.push({ y: gameState.players[id].y + 12, type: 'player', data: { player: gameState.players[id], isLocal: id === gameState.localPlayerId, isMoving: id === gameState.localPlayerId ? (window as any).isLocalMoving : false, isSprinting: id === gameState.localPlayerId ? isSprinting : false } });
  renderList.sort((a, b) => a.y - b.y);

  for (const obj of renderList) {
      if (obj.type === 'tree') {
          const dist = Math.sqrt((me.x - (obj.data.x + 70))**2 + (me.y - (obj.data.y + 110))**2);
          ctx.drawImage(textures['tree_trunk'], obj.data.x, obj.data.y, 140, 220);
          if (dist < 220 && me.y < obj.y) ctx.globalAlpha = 0.4;
          ctx.drawImage(textures['tree_canopy'], obj.data.x, obj.data.y, 140, 220); ctx.globalAlpha = 1.0; 
      } else if (obj.type === 'stone') ctx.drawImage(textures['stone'], obj.data.x - 10, obj.data.y - 10, TILE_SIZE*1.5, TILE_SIZE*1.5);
      else if (obj.type === 'big_rock') ctx.drawImage(textures['big_rock'], obj.data.x, obj.data.y, 100, 80);
      else if (obj.type === 'wall') ctx.drawImage(obj.data.tex, obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'door') {
          ctx.save(); const { x, y, angle, subType } = obj.data;
          // Убран минус перед углом для типов 'b' и 'r', чтобы они открывались в правильную сторону от игрока
          if (subType === 't') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'b') { ctx.translate(x, y + TILE_SIZE); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, -TILE_SIZE, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'l') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'r') { ctx.translate(x + TILE_SIZE, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, -TILE_SIZE, 0, TILE_SIZE, TILE_SIZE); }
          ctx.restore();
      } else if (obj.type === 'workbench') ctx.drawImage(textures['workbench'], obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'player') drawPlayer(ctx, obj.data.player, obj.data.isLocal, obj.data.isMoving, obj.data.isSprinting);
      else if (obj.type === 'ground_item') {
          const item = obj.data; ctx.save(); ctx.translate(item.x, item.y); ctx.rotate(item.rotation);
          const tex = (item.type === 'stick' || item.type === 'wood') ? textures['ground_twig'] : textures['ground_pebble'];
          if (tex) { const w = (item.type === 'stick' || item.type === 'wood') ? 32 : 16; ctx.drawImage(tex, -w/2, -w/2, w, w); }
          ctx.restore();
      }
  }

  // --- DAY/NIGHT OVERLAY ---
  ctx.restore(); // Выходим из мировых координат для полноэкранного фильтра
  ctx.save();
  const time = gameState.worldTime;
  let nightAlpha = 0;
  if (!gameState.useTestWorld && time > 14000 && time < 22000) { // В тестовом мире всегда день
      if (time < 18000) nightAlpha = (time - 14000) / 4000;
      else nightAlpha = 1 - (time - 18000) / 4000;
  }
  if (nightAlpha > 0) {
      const maxNight = 0.65;
      ctx.fillStyle = `rgba(10, 10, 40, ${nightAlpha * maxNight})`;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Легкое свечение вокруг игрока
      const gradient = ctx.createRadialGradient(logicalWidth/2, logicalHeight/2, 0, logicalWidth/2, logicalHeight/2, 200);
      gradient.addColorStop(0, 'rgba(255, 255, 200, 0.15)');
      gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.globalCompositeOperation = 'destination-out';
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.globalCompositeOperation = 'source-over';
  }
  ctx.restore();

  // Возвращаемся в мировые координаты для UI элементов над миром (прогресс добычи и т.д.)
  ctx.save();
  ctx.scale(dpr, dpr);
  ctx.translate(logicalWidth / 2, logicalHeight / 2);
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-camX, -camY);

  if (miningProgress > 0) {
      const worldX = targetX * TILE_SIZE + TILE_SIZE / 2, worldY = targetY * TILE_SIZE; 
      ctx.fillStyle = 'rgba(0,0,0,0.5)'; ctx.fillRect(worldX - 20, worldY - 15, 40, 6);
      ctx.fillStyle = '#4ade80'; ctx.fillRect(worldX - 20 + 1, worldY - 14, 38 * miningProgress, 4);
  }
  for (let i = floatingTexts.length - 1; i >= 0; i--) {
      const ft = floatingTexts[i]; ft.life--; ft.y -= 0.5; ctx.globalAlpha = ft.life / ft.maxLife;
      ctx.font = 'bold 16px sans-serif'; ctx.textAlign = 'center'; ctx.strokeStyle = 'black'; ctx.lineWidth = 3; ctx.strokeText(ft.text, ft.x, ft.y); ctx.fillStyle = ft.color; ctx.fillText(ft.text, ft.x, ft.y);
      ctx.globalAlpha = 1.0; if (ft.life <= 0) floatingTexts.splice(i, 1);
  }
  ctx.restore(); 
}

// renderer.ts: Отрисовка игрового мира и сущностей
import { TILE_SIZE } from './constants';
import { Player } from './types';
import { gameState } from './state';
import { textures, charSprites, AnimFrame } from './assets';
import { getTileData, isPositionInWater, canPlaceObject, getInteractionType } from './world';
import { getSelectedItem } from './inventory';
import { inputState } from './input';
import { placementRotation } from './interaction'; 

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;
export let cameraZoom = 1.5; 

let camX = 0;
let camY = 0;
let isCameraInitialized = false;

interface FloatingText {
    x: number; y: number; text: string; life: number; maxLife: number; color: string;
}
const floatingTexts: FloatingText[] = [];

export function addFloatingText(x: number, y: number, text: string, color: string = '#ffffff') {
    floatingTexts.push({ x, y, text, life: 60, maxLife: 60, color });
}

export function getCameraZoom() { return cameraZoom; }

export function initRenderer(canvasEl: HTMLCanvasElement) {
    canvas = canvasEl; ctx = canvas.getContext('2d');
    if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
}

export function resetCamera(x: number, y: number) {
    camX = x;
    camY = y;
    isCameraInitialized = true;
}

export function adjustZoom(deltaY: number) {
    cameraZoom -= deltaY * 0.001;
    if (cameraZoom < 0.8) cameraZoom = 0.8;
    if (cameraZoom > 3.0) cameraZoom = 3.0;
}

function getAnimationFrame(isMoving: boolean, isSprinting: boolean): AnimFrame {
    if (!isMoving) return 0;
    const frameDuration = isSprinting ? 75 : 150;
    const now = Date.now();
    const cycle = Math.floor(now / frameDuration) % 4;
    return (cycle === 3) ? 2 : (cycle as AnimFrame);
}

export function drawCharacterPreview(ctxPreview: CanvasRenderingContext2D, player: Player) {
    const w = ctxPreview.canvas.width; const h = ctxPreview.canvas.height;
    ctxPreview.clearRect(0, 0, w, h); ctxPreview.save(); ctxPreview.translate(w/2, h/2); ctxPreview.scale(1.2, 1.2); ctxPreview.translate(-32, -42); 

    // Выбираем спрайт по цвету игрока
    const baseKey = `base_${player.color}`;
    const baseSprite = (charSprites[baseKey] && charSprites[baseKey][0]) ? charSprites[baseKey][0] : (charSprites['base_#FFFFFF'] ? charSprites['base_#FFFFFF'][0] : charSprites['base'][0]);

    if (baseSprite) ctxPreview.drawImage(baseSprite, 0, 0, 64, 84);

    if (player.equipment.legs && charSprites[player.equipment.legs]) ctxPreview.drawImage(charSprites[player.equipment.legs][0], 0, 0, 64, 84);
    if (player.equipment.body && charSprites[player.equipment.body]) ctxPreview.drawImage(charSprites[player.equipment.body][0], 0, 0, 64, 84);
    if (player.equipment.head && charSprites[player.equipment.head]) ctxPreview.drawImage(charSprites[player.equipment.head][0], 0, 0, 64, 84);
    ctxPreview.restore();
}

function drawPlayer(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean, isMoving: boolean, isSprinting: boolean) {
    const isInWater = isPositionInWater(player.x, player.y);
    const x = player.x; let y = player.y;
    if (isInWater) y += 5 + Math.sin(Date.now() / 400) * 2; 
    const frame = getAnimationFrame(isMoving, isSprinting);
    const dir = player.direction || 'front';
    const isFlipped = dir === 'right';
    ctx.save(); ctx.translate(x, y);
    if (!isLocal) {
        ctx.fillStyle = '#FFFFFF'; ctx.shadowColor = 'black'; ctx.shadowBlur = 4; ctx.font = 'bold 12px sans-serif'; ctx.textAlign = 'center'; ctx.fillText(player.nickname, 0, -55); ctx.shadowBlur = 0;
    }
    if (!isInWater) { ctx.fillStyle = 'rgba(0,0,0,0.25)'; ctx.beginPath(); ctx.ellipse(0, 12, 16, 6, 0, 0, Math.PI*2); ctx.fill(); }
    else {
        const ripple = (Math.sin(Date.now() / 500) + 1) / 2;
        ctx.strokeStyle = `rgba(255, 255, 255, ${0.4 - ripple * 0.2})`; ctx.lineWidth = 2; ctx.beginPath(); ctx.ellipse(0, 0, 12 + ripple * 4, 6 + ripple * 2, 0, 0, Math.PI*2); ctx.stroke();
    }
    if (isFlipped) ctx.scale(-1, 1);
    if (isInWater) { ctx.beginPath(); ctx.rect(-40, -100, 80, 100); ctx.clip(); }
    ctx.translate(-32, -60); 

    // Выбираем правильный спрайт базы на основе цвета игрока
    const baseKey = `base_${player.color}`;
    // Fallback: если цвет не найден (например, старый кеш), берем белый
    const baseSpriteSet = charSprites[baseKey] || charSprites['base_#FFFFFF'] || charSprites['base'];

    if (baseSpriteSet && baseSpriteSet[frame]) ctx.drawImage(baseSpriteSet[frame], 0, 0, 64, 84);

    if (player.equipment) {
        if (player.equipment.legs && charSprites[player.equipment.legs]) ctx.drawImage(charSprites[player.equipment.legs][frame], 0, 0, 64, 84);
        if (player.equipment.body && charSprites[player.equipment.body]) ctx.drawImage(charSprites[player.equipment.body][frame], 0, 0, 64, 84);
        if (player.equipment.head && charSprites[player.equipment.head]) ctx.drawImage(charSprites[player.equipment.head][frame], 0, 0, 64, 84);
    }
    if (isLocal) {
        const item = getSelectedItem();
        if (item) {
            ctx.font = '24px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; 

            // Если персонаж развернут, нужно развернуть текст обратно,
            // но при этом скорректировать координату X, так как система координат смещена
            if (isFlipped) {
                ctx.scale(-1, 1);
                // В развернутой системе координат центр спрайта смещается
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, -32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            } else {
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, 32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            }
        }
    }
    ctx.restore();
}

interface RenderObject { y: number; type: string; data: any; }

function lerp(start: number, end: number, t: number) { return start * (1 - t) + end * t; }

export function renderGame(miningProgress: number = 0, targetX: number = 0, targetY: number = 0, isSprinting: boolean = false) {
  if (!ctx || !canvas) return;
  const me = gameState.players[gameState.localPlayerId];
  if (!me) return;
  if (!isCameraInitialized) { camX = me.x; camY = me.y; isCameraInitialized = true; }

  // Принудительная телепортация камеры, если она слишком далеко (например, при респавне)
  const dist = Math.sqrt((camX - me.x)**2 + (camY - me.y)**2);
  if (dist > 1000) { camX = me.x; camY = me.y; }

  const lerpFactor = isSprinting ? 0.08 : 0.15;
  camX = lerp(camX, me.x, lerpFactor); camY = lerp(camY, me.y, lerpFactor);
  const dpr = window.devicePixelRatio || 1;

  // ФОН: Если тестовый мир - белый/серый, иначе зеленый
  ctx.fillStyle = gameState.useTestWorld ? '#e2e8f0' : '#4e8c33'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  ctx.save();
  ctx.scale(dpr, dpr);
  const logicalWidth = canvas.width / dpr; const logicalHeight = canvas.height / dpr;
  ctx.translate(logicalWidth / 2, logicalHeight / 2);
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-camX, -camY);

  const viewW = logicalWidth / cameraZoom, viewH = logicalHeight / cameraZoom;
  const startTileX = Math.floor((camX - viewW/2) / TILE_SIZE) - 1;
  const endTileX = Math.floor((camX + viewW/2) / TILE_SIZE) + 2;
  const startTileY = Math.floor((camY - viewH/2) / TILE_SIZE) - 2; 
  const endTileY = Math.floor((camY + viewH/2) / TILE_SIZE) + 4;

  const renderList: RenderObject[] = [];

  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const screenX = x * TILE_SIZE, screenY = y * TILE_SIZE;
        const tileData = getTileData(x, y);

        // РЕНДЕРИНГ ПОВЕРХНОСТИ
        if (tileData.terrain === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            // --- ЛОГИКА БЕРЕГОВ (СКРУГЛЕНИЯ) ---
            const isN = getTileData(x, y - 1).terrain === 'grass';
            const isS = getTileData(x, y + 1).terrain === 'grass';
            const isW = getTileData(x - 1, y).terrain === 'grass';
            const isE = getTileData(x + 1, y).terrain === 'grass';

            if (isN && isW) ctx.drawImage(textures['mask_corner_tl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isN && isE) ctx.drawImage(textures['mask_corner_tr'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isW) ctx.drawImage(textures['mask_corner_bl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isE) ctx.drawImage(textures['mask_corner_br'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            const waveHash = Math.sin(x * 12.9898 + y * 78.233) * 43758.5453;
            if ((waveHash - Math.floor(waveHash)) > 0.85) ctx.drawImage(textures['water_wave'], screenX, screenY + Math.sin(Date.now() / 500) * 2, TILE_SIZE, TILE_SIZE);
        } else if (!gameState.useTestWorld) {
            ctx.drawImage(textures['grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.floor === 'wood') ctx.drawImage(textures['floor_wood'], screenX, screenY, TILE_SIZE, TILE_SIZE);

        if (gameState.showDebugGrid || gameState.useTestWorld) {
            ctx.strokeStyle = gameState.useTestWorld ? 'rgba(0,0,0,0.05)' : 'rgba(255,255,255,0.1)'; 
            ctx.strokeRect(screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.object === 'tree') renderList.push({ y: screenY + 35, type: 'tree', data: { x: screenX - 50, y: screenY - 180 } });
        else if (tileData.object === 'stone') renderList.push({ y: screenY + 30, type: 'stone', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'big_rock') renderList.push({ y: screenY + 38, type: 'big_rock', data: { x: screenX - 30, y: screenY - 40 } });
        else if (tileData.object === 'workbench') renderList.push({ y: screenY + 30, type: 'workbench', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'high_grass') ctx.drawImage(textures['high_grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        else if (tileData.object.startsWith('wall_wood') || tileData.object.startsWith('door_wood')) {
             let sortY = screenY + TILE_SIZE; if (tileData.object.includes('_t')) sortY = screenY + 10;
             let angle = 0; if (tileData.object.startsWith('door_wood')) { const k = `${x},${y}`; if (gameState.doorStates[k]) angle = gameState.doorStates[k].angle; }
             renderList.push({ y: sortY, type: tileData.object.startsWith('door_wood') ? 'door' : 'wall', data: { x: screenX, y: screenY, tex: textures[tileData.object], angle, subType: tileData.object.split('_').pop() } });
        }
        tileData.items.forEach((item, i) => {
            const seed = x * 1000 + y + i * 50;
            renderList.push({ y: screenY + TILE_SIZE/2, type: 'ground_item', data: { x: screenX + TILE_SIZE/2 + Math.sin(seed)*10, y: screenY + TILE_SIZE/2 + Math.cos(seed)*10, type: item, rotation: Math.sin(seed*0.1)*Math.PI } });
        });
    }
  }
  for (const id in gameState.players) renderList.push({ y: gameState.players[id].y + 12, type: 'player', data: { player: gameState.players[id], isLocal: id === gameState.localPlayerId, isMoving: id === gameState.localPlayerId ? (window as any).isLocalMoving : false, isSprinting: id === gameState.localPlayerId ? isSprinting : false } });
  renderList.sort((a, b) => a.y - b.y);

  for (const obj of renderList) {
      if (obj.type === 'tree') {
          const dist = Math.sqrt((me.x - (obj.data.x + 70))**2 + (me.y - (obj.data.y + 110))**2);
          ctx.drawImage(textures['tree_trunk'], obj.data.x, obj.data.y, 140, 220);
          if (dist < 220 && me.y < obj.y) ctx.globalAlpha = 0.4;
          ctx.drawImage(textures['tree_canopy'], obj.data.x, obj.data.y, 140, 220); ctx.globalAlpha = 1.0; 
      } else if (obj.type === 'stone') ctx.drawImage(textures['stone'], obj.data.x - 10, obj.data.y - 10, TILE_SIZE*1.5, TILE_SIZE*1.5);
      else if (obj.type === 'big_rock') ctx.drawImage(textures['big_rock'], obj.data.x, obj.data.y, 100, 80);
      else if (obj.type === 'wall') ctx.drawImage(obj.data.tex, obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'door') {
          ctx.save(); const { x, y, angle, subType } = obj.data;
          // Убран минус перед углом для типов 'b' и 'r', чтобы они открывались в правильную сторону от игрока
          if (subType === 't') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'b') { ctx.translate(x, y + TILE_SIZE); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, -TILE_SIZE, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'l') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'r') { ctx.translate(x + TILE_SIZE, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, -TILE_SIZE, 0, TILE_SIZE, TILE_SIZE); }
          ctx.restore();
      } else if (obj.type === 'workbench') ctx.drawImage(textures['workbench'], obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'player') drawPlayer(ctx, obj.data.player, obj.data.isLocal, obj.data.isMoving, obj.data.isSprinting);
      else if (obj.type === 'ground_item') {
          const item = obj.data; ctx.save(); ctx.translate(item.x, item.y); ctx.rotate(item.rotation);
          const tex = (item.type === 'stick' || item.type === 'wood') ? textures['ground_twig'] : textures['ground_pebble'];
          if (tex) { const w = (item.type === 'stick' || item.type === 'wood') ? 32 : 16; ctx.drawImage(tex, -w/2, -w/2, w, w); }
          ctx.restore();
      }
  }

  // --- DAY/NIGHT OVERLAY ---
  ctx.restore(); // Выходим из мировых координат для полноэкранного фильтра
  ctx.save();
  const time = gameState.worldTime;
  let nightAlpha = 0;
  if (!gameState.useTestWorld && time > 14000 && time < 22000) { // В тестовом мире всегда день
      if (time < 18000) nightAlpha = (time - 14000) / 4000;
      else nightAlpha = 1 - (time - 18000) / 4000;
  }
  if (nightAlpha > 0) {
      const maxNight = 0.65;
      ctx.fillStyle = `rgba(10, 10, 40, ${nightAlpha * maxNight})`;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Легкое свечение вокруг игрока
      const gradient = ctx.createRadialGradient(logicalWidth/2, logicalHeight/2, 0, logicalWidth/2, logicalHeight/2, 200);
      gradient.addColorStop(0, 'rgba(255, 255, 200, 0.15)');
      gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.globalCompositeOperation = 'destination-out';
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.globalCompositeOperation = 'source-over';
  }
  ctx.restore();

  // Возвращаемся в мировые координаты для UI элементов над миром (прогресс добычи и т.д.)
  ctx.save();
  ctx.scale(dpr, dpr);
  ctx.translate(logicalWidth / 2, logicalHeight / 2);
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-camX, -camY);

  if (miningProgress > 0) {
      const worldX = targetX * TILE_SIZE + TILE_SIZE / 2, worldY = targetY * TILE_SIZE; 
      ctx.fillStyle = 'rgba(0,0,0,0.5)'; ctx.fillRect(worldX - 20, worldY - 15, 40, 6);
      ctx.fillStyle = '#4ade80'; ctx.fillRect(worldX - 20 + 1, worldY - 14, 38 * miningProgress, 4);
  }
  for (let i = floatingTexts.length - 1; i >= 0; i--) {
      const ft = floatingTexts[i]; ft.life--; ft.y -= 0.5; ctx.globalAlpha = ft.life / ft.maxLife;
      ctx.font = 'bold 16px sans-serif'; ctx.textAlign = 'center'; ctx.strokeStyle = 'black'; ctx.lineWidth = 3; ctx.strokeText(ft.text, ft.x, ft.y); ctx.fillStyle = ft.color; ctx.fillText(ft.text, ft.x, ft.y);
      ctx.globalAlpha = 1.0; if (ft.life <= 0) floatingTexts.splice(i, 1);
  }
  ctx.restore(); 
}

// index.tsx: Главная точка входа
import { Players, Player, Direction } from './types';
import { TILE_SIZE } from './constants';
import { initInput, inputState } from './input';

// Modules
import { gameState, setPlayers, setLocalPlayerId, getLocalPlayer } from './state';
import { initRenderer, renderGame, adjustZoom, getCameraZoom, addFloatingText, resetCamera } from './renderer';
import { generateAssets } from './assets';
import { initWorld, applyWorldUpdate, canMoveTo, isPositionInWater } from './world';
import { updateDoorPhysics } from './physics'; 
import { initInventory, syncInventoryWithServer, toggleInventory, handleHotbarKey, resetInventory, isInventoryOpen, getSelectedItem, cycleHotbar } from './inventory';
import { initUI, showGameScreen, updateOnlineCount, updateRoomList } from './ui';
import { initNetwork, emitMovement } from './network';
import { isChatOpen, toggleChat, addChatMessage } from './chat';
import { handleInteraction, currentMiningProgress, currentMiningTargetX, currentMiningTargetY, placementRotation, setPlacementRotation } from './interaction';
import { PLAYER_COLORS } from './assetHuman';

const canvas = document.getElementById('game-canvas') as HTMLCanvasElement;
const gameContainer = document.getElementById('game-container') as HTMLDivElement;

const hudEls = {
    hp: document.getElementById('bar-hp-fill'),
    hunger: document.getElementById('bar-hunger-fill'),
    mana: document.getElementById('bar-mana-fill'),
    energy: document.getElementById('bar-energy-fill'),
    xp: document.getElementById('bar-xp-fill'),
    level: document.getElementById('level-val'),
    textHp: document.getElementById('text-hp'),
    textHunger: document.getElementById('text-hunger'),
    textMana: document.getElementById('text-mana'),
    textEnergy: document.getElementById('text-energy')
};

const BASE_WALK_SPEED = 3;
const BASE_SPRINT_SPEED = 6;
let fps = 0;
let lastLoop = 0;
const fpsEl = document.getElementById('fps-counter');
let lastRotateTime = 0;

document.addEventListener('DOMContentLoaded', () => {
    initRenderer(canvas);
    generateAssets();
    initInventory();

    const movement = initInput(canvas);

    initUI({ onStartOffline: startGameOffline });

    initNetwork({
        onConnect: (id) => setLocalPlayerId(id),
        onOnlineCount: updateOnlineCount,
        onRoomList: updateRoomList,
        onGameStart: (players, worldChanges, seed) => {
            gameState.isOffline = false;
            if (seed) gameState.worldSeed = seed;
            if (worldChanges) worldChanges.forEach(update => applyWorldUpdate(update));
            startGame(players, gameState.localPlayerId);
            addChatMessage("SYSTEM", `Welcome to Terra Wilds! Seed: ${gameState.worldSeed}`, "#fbbf24", true);
        },
        onState: (serverPlayers, serverTime) => {
            const me = getLocalPlayer();
            const serverMe = serverPlayers[gameState.localPlayerId];

            // Синхронизация времени с сервера
            if (typeof serverTime === 'number') {
                gameState.worldTime = serverTime;
            }

            if (me && serverMe) {
                if (serverMe.inventory) syncInventoryWithServer(serverMe.inventory);
                if (serverMe.stats) {
                    me.stats.hp = serverMe.stats.hp;
                    me.stats.maxHp = serverMe.stats.maxHp;
                    me.stats.hunger = serverMe.stats.hunger;
                    me.stats.xp = serverMe.stats.xp;
                    me.stats.level = serverMe.stats.level;
                    if (Math.abs(me.stats.energy - serverMe.stats.energy) > 5) me.stats.energy = serverMe.stats.energy;
                }
                const dist = Math.sqrt(Math.pow(me.x - serverMe.x, 2) + Math.pow(me.y - serverMe.y, 2));
                if (dist > 150) { me.x = serverMe.x; me.y = serverMe.y; }
                else serverPlayers[gameState.localPlayerId] = me;
            }
            setPlayers(serverPlayers);
        },
        onWorldUpdate: (update) => applyWorldUpdate(update),
        onError: (msg) => alert(`Ошибка: ${msg}`),
        onDebugLog: (msg) => console.error(msg),
        onChatMessage: (data) => addChatMessage(data.nickname, data.text, data.color)
    });

    window.addEventListener('resize', resizeCanvas);
    canvas.addEventListener('wheel', (e) => {
        if (!gameContainer.classList.contains('hidden')) { e.preventDefault(); adjustZoom(e.deltaY); }
    }, { passive: false });

    window.addEventListener('keydown', (e) => {
        const startScreen = document.getElementById('start-screen');
        if (startScreen && startScreen.classList.contains('hidden')) {
            if (!isChatOpen && (e.code === 'Enter' || e.code === 'KeyT')) { e.preventDefault(); toggleChat(true); return; }
            if (e.code === 'Escape') { if (isChatOpen) toggleChat(false); else if (isInventoryOpen) toggleInventory(); return; }
            if (isChatOpen) return;
            if (e.code === 'Tab') { e.preventDefault(); toggleInventory(); }
            if (e.code === 'KeyQ') cycleHotbar(-1);
            if (e.code === 'KeyE') cycleHotbar(1);
            if (e.key >= '1' && e.key <= '9') handleHotbarKey(parseInt(e.key) - 1);
        }
    });

    function resizeCanvas() { 
        const dpr = window.devicePixelRatio || 1;
        canvas.width = window.innerWidth * dpr; canvas.height = window.innerHeight * dpr;
        canvas.style.width = window.innerWidth + 'px'; canvas.style.height = window.innerHeight + 'px';
        const ctx = canvas.getContext('2d');
        if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
    }

    function startGame(initialPlayers: Players, playerId: string) {
        setPlayers(initialPlayers);
        setLocalPlayerId(playerId);
        resetInventory();
        const me = initialPlayers[playerId];
        if (me && me.inventory) syncInventoryWithServer(me.inventory);
        initWorld(me.x, me.y);
        showGameScreen();
        resizeCanvas();
        resetCamera(me.x, me.y); // Центрируем камеру на старте
        if (fpsEl) fpsEl.classList.remove('hidden');
        gameLoop();
    }

    function startGameOffline() {
        const pid = 'offline_hero';
        if (!gameState.worldSeed || gameState.worldSeed === 'terrawilds') gameState.worldSeed = Math.floor(Math.random() * 1999999999 - 999999999).toString();
        const player: Player = {
            id: pid, x: 0, y: 0, 
            color: PLAYER_COLORS[Math.floor(Math.random() * PLAYER_COLORS.length)], 
            nickname: "Explorer", direction: 'front',
            inventory: [], equipment: { head: null, body: null, legs: null },
            stats: { hp: 20, maxHp: 20, hunger: 20, maxHunger: 20, mana: 20, maxMana: 20, energy: 20, maxEnergy: 20, xp: 0, maxXp: 100, level: 1 }
        };
        startGame({ [pid]: player }, pid);
        if (gameState.useTestWorld) {
            const debugPanel = document.getElementById('debug-panel');
            if (debugPanel) debugPanel.style.display = 'block';
            addChatMessage("DEV", "ТЕСТОВЫЙ МИР: Бесконечные ресурсы и респавн включены.", "#60a5fa", true);
        } else {
            addChatMessage("AI", "Мир готов! Смена дня и ночи запущена. Загляни в дебаг-меню (/debug) для управления временем!", "#10b981");
        }
    }

    function gameLoop() {
        if (gameContainer.classList.contains('hidden')) return;
        const now = performance.now();
        const delta = now - lastLoop;
        lastLoop = now;

        // Продвижение времени (только в офлайне, в онлайне берем с сервера)
        if (gameState.isOffline && !gameState.isTimePaused) {
            gameState.worldTime = (gameState.worldTime + 5) % 24000;
        }

        const me = getLocalPlayer();
        if (me) {
            if (movement.rotate && now - lastRotateTime > 200) { setPlacementRotation((placementRotation + 1) % 4); lastRotateTime = now; }
            handleInteraction(me);
            updateDoorPhysics(); 
            let canSprint = false; let currentSpeed = BASE_WALK_SPEED; let dx = 0, dy = 0; let newDir: Direction = me.direction;
            if (!isChatOpen) {
                if (me.stats) {
                    if (movement.sprint && me.stats.energy > 0) { canSprint = true; me.stats.energy -= 0.15; }
                    else if (!movement.sprint && me.stats.energy < me.stats.maxEnergy) me.stats.energy += 0.1;
                }
                currentSpeed = (canSprint ? BASE_SPRINT_SPEED : BASE_WALK_SPEED) * gameState.debug.speedMult;
                if (isPositionInWater(me.x, me.y)) currentSpeed *= 0.5;
                if (movement.up) { dy -= currentSpeed; newDir = 'back'; }
                if (movement.down) { dy += currentSpeed; newDir = 'front'; }
                if (movement.left) { dx -= currentSpeed; newDir = 'left'; }
                if (movement.right) { dx += currentSpeed; newDir = 'right'; }
            }
            if (dx !== 0 || dy !== 0) { 
                me.direction = newDir; (window as any).isLocalMoving = true; 
                if (dx !== 0 && canMoveTo(me.x + dx, me.y, 32, 32)) me.x += dx;
                if (dy !== 0 && canMoveTo(me.x, me.y + dy, 32, 32)) me.y += dy;
            } else (window as any).isLocalMoving = false;
            if (!gameState.isOffline) emitMovement({ x: me.x, y: me.y, direction: me.direction, sprint: canSprint });
            if (me.stats && hudEls.hp) {
                hudEls.hp.style.width = `${(me.stats.hp / me.stats.maxHp) * 100}%`;
                hudEls.hunger!.style.width = `${(me.stats.hunger / me.stats.maxHunger) * 100}%`;
                hudEls.mana!.style.width = `${(me.stats.mana / me.stats.maxMana) * 100}%`;
                hudEls.energy!.style.width = `${(me.stats.energy / me.stats.maxEnergy) * 100}%`;
                hudEls.xp!.style.width = `${(me.stats.xp / me.stats.maxXp) * 100}%`;
                hudEls.textHp!.textContent = String(Math.floor(me.stats.hp));
                hudEls.textHunger!.textContent = String(Math.floor(me.stats.hunger));
                hudEls.textEnergy!.textContent = String(Math.floor(me.stats.energy));
                hudEls.level!.textContent = String(me.stats.level);
            }
        }
        renderGame(currentMiningProgress, currentMiningTargetX, currentMiningTargetY, !isChatOpen && movement.sprint && me?.stats && me.stats.energy > 0);
        requestAnimationFrame(gameLoop);
    }
});

// renderer.ts: Отрисовка игрового мира и сущностей
import { TILE_SIZE } from './constants';
import { Player } from './types';
import { gameState } from './state';
import { textures, charSprites, AnimFrame } from './assets';
import { getTileData, isPositionInWater, canPlaceObject, getInteractionType } from './world';
import { getSelectedItem } from './inventory';
import { inputState } from './input';
import { placementRotation } from './interaction'; 

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;
export let cameraZoom = 1.5; 

let camX = 0;
let camY = 0;
let isCameraInitialized = false;
let shouldSnapCamera = false; // Флаг для мгновенной центровки

interface FloatingText {
    x: number; y: number; text: string; life: number; maxLife: number; color: string;
}
const floatingTexts: FloatingText[] = [];

export function addFloatingText(x: number, y: number, text: string, color: string = '#ffffff') {
    floatingTexts.push({ x, y, text, life: 60, maxLife: 60, color });
}

export function getCameraZoom() { return cameraZoom; }

export function initRenderer(canvasEl: HTMLCanvasElement) {
    canvas = canvasEl; ctx = canvas.getContext('2d');
    if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
}

export function resetCamera(x: number, y: number) {
    camX = x;
    camY = y;
    isCameraInitialized = true;
    shouldSnapCamera = true; // Принудительно центрируем в следующем кадре
}

export function adjustZoom(deltaY: number) {
    cameraZoom -= deltaY * 0.001;
    if (cameraZoom < 0.8) cameraZoom = 0.8;
    if (cameraZoom > 3.0) cameraZoom = 3.0;
}

function getAnimationFrame(isMoving: boolean, isSprinting: boolean): AnimFrame {
    if (!isMoving) return 0;
    const frameDuration = isSprinting ? 75 : 150;
    const now = Date.now();
    const cycle = Math.floor(now / frameDuration) % 4;
    return (cycle === 3) ? 2 : (cycle as AnimFrame);
}

export function drawCharacterPreview(ctxPreview: CanvasRenderingContext2D, player: Player) {
    const w = ctxPreview.canvas.width; const h = ctxPreview.canvas.height;
    ctxPreview.clearRect(0, 0, w, h); ctxPreview.save(); ctxPreview.translate(w/2, h/2); ctxPreview.scale(1.2, 1.2); ctxPreview.translate(-32, -42); 

    // Выбираем спрайт по цвету игрока
    const baseKey = `base_${player.color}`;
    const baseSprite = (charSprites[baseKey] && charSprites[baseKey][0]) ? charSprites[baseKey][0] : (charSprites['base_#FFFFFF'] ? charSprites['base_#FFFFFF'][0] : charSprites['base'][0]);

    if (baseSprite) ctxPreview.drawImage(baseSprite, 0, 0, 64, 84);

    if (player.equipment.legs && charSprites[player.equipment.legs]) ctxPreview.drawImage(charSprites[player.equipment.legs][0], 0, 0, 64, 84);
    if (player.equipment.body && charSprites[player.equipment.body]) ctxPreview.drawImage(charSprites[player.equipment.body][0], 0, 0, 64, 84);
    if (player.equipment.head && charSprites[player.equipment.head]) ctxPreview.drawImage(charSprites[player.equipment.head][0], 0, 0, 64, 84);
    ctxPreview.restore();
}

function drawPlayer(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean, isMoving: boolean, isSprinting: boolean) {
    const isInWater = isPositionInWater(player.x, player.y);
    const x = player.x; let y = player.y;
    if (isInWater) y += 5 + Math.sin(Date.now() / 400) * 2; 
    const frame = getAnimationFrame(isMoving, isSprinting);
    const dir = player.direction || 'front';
    const isFlipped = dir === 'right';
    ctx.save(); ctx.translate(x, y);
    if (!isLocal) {
        ctx.fillStyle = '#FFFFFF'; ctx.shadowColor = 'black'; ctx.shadowBlur = 4; ctx.font = 'bold 12px sans-serif'; ctx.textAlign = 'center'; ctx.fillText(player.nickname, 0, -55); ctx.shadowBlur = 0;
    }
    if (!isInWater) { ctx.fillStyle = 'rgba(0,0,0,0.25)'; ctx.beginPath(); ctx.ellipse(0, 12, 16, 6, 0, 0, Math.PI*2); ctx.fill(); }
    else {
        const ripple = (Math.sin(Date.now() / 500) + 1) / 2;
        ctx.strokeStyle = `rgba(255, 255, 255, ${0.4 - ripple * 0.2})`; ctx.lineWidth = 2; ctx.beginPath(); ctx.ellipse(0, 0, 12 + ripple * 4, 6 + ripple * 2, 0, 0, Math.PI*2); ctx.stroke();
    }
    if (isFlipped) ctx.scale(-1, 1);
    if (isInWater) { ctx.beginPath(); ctx.rect(-40, -100, 80, 100); ctx.clip(); }
    ctx.translate(-32, -60); 

    // Выбираем правильный спрайт базы на основе цвета игрока
    const baseKey = `base_${player.color}`;
    // Fallback: если цвет не найден (например, старый кеш), берем белый
    const baseSpriteSet = charSprites[baseKey] || charSprites['base_#FFFFFF'] || charSprites['base'];

    if (baseSpriteSet && baseSpriteSet[frame]) ctx.drawImage(baseSpriteSet[frame], 0, 0, 64, 84);

    if (player.equipment) {
        if (player.equipment.legs && charSprites[player.equipment.legs]) ctx.drawImage(charSprites[player.equipment.legs][frame], 0, 0, 64, 84);
        if (player.equipment.body && charSprites[player.equipment.body]) ctx.drawImage(charSprites[player.equipment.body][frame], 0, 0, 64, 84);
        if (player.equipment.head && charSprites[player.equipment.head]) ctx.drawImage(charSprites[player.equipment.head][frame], 0, 0, 64, 84);
    }
    if (isLocal) {
        const item = getSelectedItem();
        if (item) {
            ctx.font = '24px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; 

            // Если персонаж развернут, нужно развернуть текст обратно,
            // но при этом скорректировать координату X, так как система координат смещена
            if (isFlipped) {
                ctx.scale(-1, 1);
                // В развернутой системе координат центр спрайта смещается
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, -32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            } else {
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, 32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            }
        }
    }
    ctx.restore();
}

interface RenderObject { y: number; type: string; data: any; }

function lerp(start: number, end: number, t: number) { return start * (1 - t) + end * t; }

export function renderGame(miningProgress: number = 0, targetX: number = 0, targetY: number = 0, isSprinting: boolean = false) {
  if (!ctx || !canvas) return;
  const me = gameState.players[gameState.localPlayerId];
  if (!me) return;

  // Инициализация или принудительная центровка
  if (!isCameraInitialized || shouldSnapCamera) {
      camX = me.x;
      camY = me.y;
      isCameraInitialized = true;
      shouldSnapCamera = false;
  }

  // Принудительная телепортация камеры, если она слишком далеко (порог уменьшен до 500)
  const dist = Math.sqrt((camX - me.x)**2 + (camY - me.y)**2);
  if (dist > 500) { camX = me.x; camY = me.y; }

  const lerpFactor = isSprinting ? 0.08 : 0.15;
  camX = lerp(camX, me.x, lerpFactor); camY = lerp(camY, me.y, lerpFactor);

  // Защита от NaN
  if (isNaN(camX)) camX = me.x;
  if (isNaN(camY)) camY = me.y;

  const dpr = window.devicePixelRatio || 1;

  // ФОН: Если тестовый мир - белый/серый, иначе зеленый
  ctx.fillStyle = gameState.useTestWorld ? '#e2e8f0' : '#4e8c33'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  ctx.save();
  ctx.scale(dpr, dpr);
  const logicalWidth = canvas.width / dpr; const logicalHeight = canvas.height / dpr;
  ctx.translate(logicalWidth / 2, logicalHeight / 2);
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-camX, -camY);

  const viewW = logicalWidth / cameraZoom, viewH = logicalHeight / cameraZoom;
  const startTileX = Math.floor((camX - viewW/2) / TILE_SIZE) - 1;
  const endTileX = Math.floor((camX + viewW/2) / TILE_SIZE) + 2;
  const startTileY = Math.floor((camY - viewH/2) / TILE_SIZE) - 2; 
  const endTileY = Math.floor((camY + viewH/2) / TILE_SIZE) + 4;

  const renderList: RenderObject[] = [];

  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const screenX = x * TILE_SIZE, screenY = y * TILE_SIZE;
        const tileData = getTileData(x, y);

        // РЕНДЕРИНГ ПОВЕРХНОСТИ
        if (tileData.terrain === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            // --- ЛОГИКА БЕРЕГОВ (СКРУГЛЕНИЯ) ---
            const isN = getTileData(x, y - 1).terrain === 'grass';
            const isS = getTileData(x, y + 1).terrain === 'grass';
            const isW = getTileData(x - 1, y).terrain === 'grass';
            const isE = getTileData(x + 1, y).terrain === 'grass';

            if (isN && isW) ctx.drawImage(textures['mask_corner_tl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isN && isE) ctx.drawImage(textures['mask_corner_tr'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isW) ctx.drawImage(textures['mask_corner_bl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isE) ctx.drawImage(textures['mask_corner_br'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            const waveHash = Math.sin(x * 12.9898 + y * 78.233) * 43758.5453;
            if ((waveHash - Math.floor(waveHash)) > 0.85) ctx.drawImage(textures['water_wave'], screenX, screenY + Math.sin(Date.now() / 500) * 2, TILE_SIZE, TILE_SIZE);
        } else if (!gameState.useTestWorld) {
            ctx.drawImage(textures['grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.floor === 'wood') ctx.drawImage(textures['floor_wood'], screenX, screenY, TILE_SIZE, TILE_SIZE);

        if (gameState.showDebugGrid || gameState.useTestWorld) {
            ctx.strokeStyle = gameState.useTestWorld ? 'rgba(0,0,0,0.05)' : 'rgba(255,255,255,0.1)'; 
            ctx.strokeRect(screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.object === 'tree') renderList.push({ y: screenY + 35, type: 'tree', data: { x: screenX - 50, y: screenY - 180 } });
        else if (tileData.object === 'stone') renderList.push({ y: screenY + 30, type: 'stone', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'big_rock') renderList.push({ y: screenY + 38, type: 'big_rock', data: { x: screenX - 30, y: screenY - 40 } });
        else if (tileData.object === 'workbench') renderList.push({ y: screenY + 30, type: 'workbench', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'high_grass') ctx.drawImage(textures['high_grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        else if (tileData.object.startsWith('wall_wood') || tileData.object.startsWith('door_wood')) {
             let sortY = screenY + TILE_SIZE; if (tileData.object.includes('_t')) sortY = screenY + 10;
             let angle = 0; if (tileData.object.startsWith('door_wood')) { const k = `${x},${y}`; if (gameState.doorStates[k]) angle = gameState.doorStates[k].angle; }
             renderList.push({ y: sortY, type: tileData.object.startsWith('door_wood') ? 'door' : 'wall', data: { x: screenX, y: screenY, tex: textures[tileData.object], angle, subType: tileData.object.split('_').pop() } });
        }
        tileData.items.forEach((item, i) => {
            const seed = x * 1000 + y + i * 50;
            renderList.push({ y: screenY + TILE_SIZE/2, type: 'ground_item', data: { x: screenX + TILE_SIZE/2 + Math.sin(seed)*10, y: screenY + TILE_SIZE/2 + Math.cos(seed)*10, type: item, rotation: Math.sin(seed*0.1)*Math.PI } });
        });
    }
  }
  for (const id in gameState.players) renderList.push({ y: gameState.players[id].y + 12, type: 'player', data: { player: gameState.players[id], isLocal: id === gameState.localPlayerId, isMoving: id === gameState.localPlayerId ? (window as any).isLocalMoving : false, isSprinting: id === gameState.localPlayerId ? isSprinting : false } });
  renderList.sort((a, b) => a.y - b.y);

  for (const obj of renderList) {
      if (obj.type === 'tree') {
          const dist = Math.sqrt((me.x - (obj.data.x + 70))**2 + (me.y - (obj.data.y + 110))**2);
          ctx.drawImage(textures['tree_trunk'], obj.data.x, obj.data.y, 140, 220);
          if (dist < 220 && me.y < obj.y) ctx.globalAlpha = 0.4;
          ctx.drawImage(textures['tree_canopy'], obj.data.x, obj.data.y, 140, 220); ctx.globalAlpha = 1.0; 
      } else if (obj.type === 'stone') ctx.drawImage(textures['stone'], obj.data.x - 10, obj.data.y - 10, TILE_SIZE*1.5, TILE_SIZE*1.5);
      else if (obj.type === 'big_rock') ctx.drawImage(textures['big_rock'], obj.data.x, obj.data.y, 100, 80);
      else if (obj.type === 'wall') ctx.drawImage(obj.data.tex, obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'door') {
          ctx.save(); const { x, y, angle, subType } = obj.data;
          // Убран минус перед углом для типов 'b' и 'r', чтобы они открывались в правильную сторону от игрока
          if (subType === 't') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'b') { ctx.translate(x, y + TILE_SIZE); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, -TILE_SIZE, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'l') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'r') { ctx.translate(x + TILE_SIZE, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, -TILE_SIZE, 0, TILE_SIZE, TILE_SIZE); }
          ctx.restore();
      } else if (obj.type === 'workbench') ctx.drawImage(textures['workbench'], obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'player') drawPlayer(ctx, obj.data.player, obj.data.isLocal, obj.data.isMoving, obj.data.isSprinting);
      else if (obj.type === 'ground_item') {
          const item = obj.data; ctx.save(); ctx.translate(item.x, item.y); ctx.rotate(item.rotation);
          const tex = (item.type === 'stick' || item.type === 'wood') ? textures['ground_twig'] : textures['ground_pebble'];
          if (tex) { const w = (item.type === 'stick' || item.type === 'wood') ? 32 : 16; ctx.drawImage(tex, -w/2, -w/2, w, w); }
          ctx.restore();
      }
  }

  // --- DAY/NIGHT OVERLAY ---
  ctx.restore(); // Выходим из мировых координат для полноэкранного фильтра
  ctx.save();
  const time = gameState.worldTime;
  let nightAlpha = 0;
  if (!gameState.useTestWorld && time > 14000 && time < 22000) { // В тестовом мире всегда день
      if (time < 18000) nightAlpha = (time - 14000) / 4000;
      else nightAlpha = 1 - (time - 18000) / 4000;
  }
  if (nightAlpha > 0) {
      const maxNight = 0.65;
      ctx.fillStyle = `rgba(10, 10, 40, ${nightAlpha * maxNight})`;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Легкое свечение вокруг игрока
      const gradient = ctx.createRadialGradient(logicalWidth/2, logicalHeight/2, 0, logicalWidth/2, logicalHeight/2, 200);
      gradient.addColorStop(0, 'rgba(255, 255, 200, 0.15)');
      gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.globalCompositeOperation = 'destination-out';
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.globalCompositeOperation = 'source-over';
  }
  ctx.restore();

  // Возвращаемся в мировые координаты для UI элементов над миром (прогресс добычи и т.д.)
  ctx.save();
  ctx.scale(dpr, dpr);
  ctx.translate(logicalWidth / 2, logicalHeight / 2);
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-camX, -camY);

  if (miningProgress > 0) {
      const worldX = targetX * TILE_SIZE + TILE_SIZE / 2, worldY = targetY * TILE_SIZE; 
      ctx.fillStyle = 'rgba(0,0,0,0.5)'; ctx.fillRect(worldX - 20, worldY - 15, 40, 6);
      ctx.fillStyle = '#4ade80'; ctx.fillRect(worldX - 20 + 1, worldY - 14, 38 * miningProgress, 4);
  }
  for (let i = floatingTexts.length - 1; i >= 0; i--) {
      const ft = floatingTexts[i]; ft.life--; ft.y -= 0.5; ctx.globalAlpha = ft.life / ft.maxLife;
      ctx.font = 'bold 16px sans-serif'; ctx.textAlign = 'center'; ctx.strokeStyle = 'black'; ctx.lineWidth = 3; ctx.strokeText(ft.text, ft.x, ft.y); ctx.fillStyle = ft.color; ctx.fillText(ft.text, ft.x, ft.y);
      ctx.globalAlpha = 1.0; if (ft.life <= 0) floatingTexts.splice(i, 1);
  }
  ctx.restore(); 
}

// index.tsx: Главная точка входа
import { Players, Player, Direction } from './types';
import { TILE_SIZE } from './constants';
import { initInput, inputState } from './input';

// Modules
import { gameState, setPlayers, setLocalPlayerId, getLocalPlayer } from './state';
import { initRenderer, renderGame, adjustZoom, getCameraZoom, addFloatingText, resetCamera } from './renderer';
import { generateAssets } from './assets';
import { initWorld, applyWorldUpdate, canMoveTo, isPositionInWater } from './world';
import { updateDoorPhysics } from './physics'; 
import { initInventory, syncInventoryWithServer, toggleInventory, handleHotbarKey, resetInventory, isInventoryOpen, getSelectedItem, cycleHotbar } from './inventory';
import { initUI, showGameScreen, updateOnlineCount, updateRoomList } from './ui';
import { initNetwork, emitMovement } from './network';
import { isChatOpen, toggleChat, addChatMessage } from './chat';
import { handleInteraction, currentMiningProgress, currentMiningTargetX, currentMiningTargetY, placementRotation, setPlacementRotation } from './interaction';
import { PLAYER_COLORS } from './assetHuman';

const canvas = document.getElementById('game-canvas') as HTMLCanvasElement;
const gameContainer = document.getElementById('game-container') as HTMLDivElement;

const hudEls = {
    hp: document.getElementById('bar-hp-fill'),
    hunger: document.getElementById('bar-hunger-fill'),
    mana: document.getElementById('bar-mana-fill'),
    energy: document.getElementById('bar-energy-fill'),
    xp: document.getElementById('bar-xp-fill'),
    level: document.getElementById('level-val'),
    textHp: document.getElementById('text-hp'),
    textHunger: document.getElementById('text-hunger'),
    textMana: document.getElementById('text-mana'),
    textEnergy: document.getElementById('text-energy')
};

const BASE_WALK_SPEED = 3;
const BASE_SPRINT_SPEED = 6;
let fps = 0;
let lastLoop = 0;
let isGameRunning = false;
const fpsEl = document.getElementById('fps-counter');
let lastRotateTime = 0;

document.addEventListener('DOMContentLoaded', () => {
    initRenderer(canvas);
    generateAssets();
    initInventory();

    // Сразу устанавливаем размеры канваса, чтобы избежать проблем с координатами
    resizeCanvas();

    const movement = initInput(canvas);

    initUI({ onStartOffline: startGameOffline });

    initNetwork({
        onConnect: (id) => setLocalPlayerId(id),
        onOnlineCount: updateOnlineCount,
        onRoomList: updateRoomList,
        onGameStart: (players, worldChanges, seed) => {
            gameState.isOffline = false;
            if (seed) gameState.worldSeed = seed;
            if (worldChanges) worldChanges.forEach(update => applyWorldUpdate(update));
            startGame(players, gameState.localPlayerId);
            addChatMessage("SYSTEM", `Welcome to Terra Wilds! Seed: ${gameState.worldSeed}`, "#fbbf24", true);
        },
        onState: (serverPlayers, serverTime) => {
            const me = getLocalPlayer();
            const serverMe = serverPlayers[gameState.localPlayerId];

            // Синхронизация времени с сервера
            if (typeof serverTime === 'number') {
                gameState.worldTime = serverTime;
            }

            if (me && serverMe) {
                if (serverMe.inventory) syncInventoryWithServer(serverMe.inventory);
                if (serverMe.stats) {
                    me.stats.hp = serverMe.stats.hp;
                    me.stats.maxHp = serverMe.stats.maxHp;
                    me.stats.hunger = serverMe.stats.hunger;
                    me.stats.xp = serverMe.stats.xp;
                    me.stats.level = serverMe.stats.level;
                    if (Math.abs(me.stats.energy - serverMe.stats.energy) > 5) me.stats.energy = serverMe.stats.energy;
                }
                const dist = Math.sqrt(Math.pow(me.x - serverMe.x, 2) + Math.pow(me.y - serverMe.y, 2));
                if (dist > 150) { me.x = serverMe.x; me.y = serverMe.y; }
                else serverPlayers[gameState.localPlayerId] = me;
            }
            setPlayers(serverPlayers);
        },
        onWorldUpdate: (update) => applyWorldUpdate(update),
        onError: (msg) => alert(`Ошибка: ${msg}`),
        onDebugLog: (msg) => console.error(msg),
        onChatMessage: (data) => addChatMessage(data.nickname, data.text, data.color)
    });

    window.addEventListener('resize', resizeCanvas);
    canvas.addEventListener('wheel', (e) => {
        if (!gameContainer.classList.contains('hidden')) { e.preventDefault(); adjustZoom(e.deltaY); }
    }, { passive: false });

    window.addEventListener('keydown', (e) => {
        const startScreen = document.getElementById('start-screen');
        if (startScreen && startScreen.classList.contains('hidden')) {
            if (!isChatOpen && (e.code === 'Enter' || e.code === 'KeyT')) { e.preventDefault(); toggleChat(true); return; }
            if (e.code === 'Escape') { if (isChatOpen) toggleChat(false); else if (isInventoryOpen) toggleInventory(); return; }
            if (isChatOpen) return;
            if (e.code === 'Tab') { e.preventDefault(); toggleInventory(); }
            if (e.code === 'KeyQ') cycleHotbar(-1);
            if (e.code === 'KeyE') cycleHotbar(1);
            if (e.key >= '1' && e.key <= '9') handleHotbarKey(parseInt(e.key) - 1);
        }
    });

    function resizeCanvas() { 
        const dpr = window.devicePixelRatio || 1;
        canvas.width = window.innerWidth * dpr; canvas.height = window.innerHeight * dpr;
        canvas.style.width = window.innerWidth + 'px'; canvas.style.height = window.innerHeight + 'px';
        const ctx = canvas.getContext('2d');
        if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
    }

    function startGame(initialPlayers: Players, playerId: string) {
        setPlayers(initialPlayers);
        setLocalPlayerId(playerId);
        resetInventory();
        const me = initialPlayers[playerId];
        if (me && me.inventory) syncInventoryWithServer(me.inventory);
        initWorld(me.x, me.y);
        showGameScreen();
        resizeCanvas();
        resetCamera(me.x, me.y); // Центрируем камеру на старте
        if (fpsEl) fpsEl.classList.remove('hidden');

        // Запускаем цикл только если он еще не запущен
        if (!isGameRunning) {
            isGameRunning = true;
            gameLoop();
        }
    }

    function startGameOffline() {
        const pid = 'offline_hero';
        if (!gameState.worldSeed || gameState.worldSeed === 'terrawilds') gameState.worldSeed = Math.floor(Math.random() * 1999999999 - 999999999).toString();
        const player: Player = {
            id: pid, x: 0, y: 0, 
            color: PLAYER_COLORS[Math.floor(Math.random() * PLAYER_COLORS.length)], 
            nickname: "Explorer", direction: 'front',
            inventory: [], equipment: { head: null, body: null, legs: null },
            stats: { hp: 20, maxHp: 20, hunger: 20, maxHunger: 20, mana: 20, maxMana: 20, energy: 20, maxEnergy: 20, xp: 0, maxXp: 100, level: 1 }
        };
        startGame({ [pid]: player }, pid);
        if (gameState.useTestWorld) {
            const debugPanel = document.getElementById('debug-panel');
            if (debugPanel) debugPanel.style.display = 'block';
            addChatMessage("DEV", "ТЕСТОВЫЙ МИР: Бесконечные ресурсы и респавн включены.", "#60a5fa", true);
        } else {
            addChatMessage("AI", "Мир готов! Смена дня и ночи запущена. Загляни в дебаг-меню (/debug) для управления временем!", "#10b981");
        }
    }

    function gameLoop() {
        if (gameContainer.classList.contains('hidden')) {
            isGameRunning = false;
            return;
        }
        const now = performance.now();
        const delta = now - lastLoop;
        lastLoop = now;

        // Продвижение времени (только в офлайне, в онлайне берем с сервера)
        if (gameState.isOffline && !gameState.isTimePaused) {
            gameState.worldTime = (gameState.worldTime + 5) % 24000;
        }

        const me = getLocalPlayer();
        if (me) {
            if (movement.rotate && now - lastRotateTime > 200) { setPlacementRotation((placementRotation + 1) % 4); lastRotateTime = now; }
            handleInteraction(me);
            updateDoorPhysics(); 
            let canSprint = false; let currentSpeed = BASE_WALK_SPEED; let dx = 0, dy = 0; let newDir: Direction = me.direction;
            if (!isChatOpen) {
                if (me.stats) {
                    if (movement.sprint && me.stats.energy > 0) { canSprint = true; me.stats.energy -= 0.15; }
                    else if (!movement.sprint && me.stats.energy < me.stats.maxEnergy) me.stats.energy += 0.1;
                }
                currentSpeed = (canSprint ? BASE_SPRINT_SPEED : BASE_WALK_SPEED) * gameState.debug.speedMult;
                if (isPositionInWater(me.x, me.y)) currentSpeed *= 0.5;
                if (movement.up) { dy -= currentSpeed; newDir = 'back'; }
                if (movement.down) { dy += currentSpeed; newDir = 'front'; }
                if (movement.left) { dx -= currentSpeed; newDir = 'left'; }
                if (movement.right) { dx += currentSpeed; newDir = 'right'; }
            }
            if (dx !== 0 || dy !== 0) { 
                me.direction = newDir; (window as any).isLocalMoving = true; 
                if (dx !== 0 && canMoveTo(me.x + dx, me.y, 32, 32)) me.x += dx;
                if (dy !== 0 && canMoveTo(me.x, me.y + dy, 32, 32)) me.y += dy;
            } else (window as any).isLocalMoving = false;
            if (!gameState.isOffline) emitMovement({ x: me.x, y: me.y, direction: me.direction, sprint: canSprint });
            if (me.stats && hudEls.hp) {
                hudEls.hp.style.width = `${(me.stats.hp / me.stats.maxHp) * 100}%`;
                hudEls.hunger!.style.width = `${(me.stats.hunger / me.stats.maxHunger) * 100}%`;
                hudEls.mana!.style.width = `${(me.stats.mana / me.stats.maxMana) * 100}%`;
                hudEls.energy!.style.width = `${(me.stats.energy / me.stats.maxEnergy) * 100}%`;
                hudEls.xp!.style.width = `${(me.stats.xp / me.stats.maxXp) * 100}%`;
                hudEls.textHp!.textContent = String(Math.floor(me.stats.hp));
                hudEls.textHunger!.textContent = String(Math.floor(me.stats.hunger));
                hudEls.textEnergy!.textContent = String(Math.floor(me.stats.energy));
                hudEls.level!.textContent = String(me.stats.level);
            }
        }
        renderGame(currentMiningProgress, currentMiningTargetX, currentMiningTargetY, !isChatOpen && movement.sprint && me?.stats && me.stats.energy > 0);
        requestAnimationFrame(gameLoop);
    }
});

// renderer.ts: Отрисовка игрового мира и сущностей
import { TILE_SIZE } from './constants';
import { Player } from './types';
import { gameState } from './state';
import { textures, charSprites, AnimFrame } from './assets';
import { getTileData, isPositionInWater, canPlaceObject, getInteractionType } from './world';
import { getSelectedItem } from './inventory';
import { inputState } from './input';
import { placementRotation } from './interaction'; 

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;
export let cameraZoom = 1.5; 

let camX = 0;
let camY = 0;
let isCameraInitialized = false;
let snapFrames = 0; // Счетчик кадров для принудительной центровки

interface FloatingText {
    x: number; y: number; text: string; life: number; maxLife: number; color: string;
}
const floatingTexts: FloatingText[] = [];

export function addFloatingText(x: number, y: number, text: string, color: string = '#ffffff') {
    floatingTexts.push({ x, y, text, life: 60, maxLife: 60, color });
}

export function getCameraZoom() { return cameraZoom; }

export function initRenderer(canvasEl: HTMLCanvasElement) {
    canvas = canvasEl; ctx = canvas.getContext('2d');
    if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
}

export function resetCamera(x: number, y: number) {
    camX = x;
    camY = y;
    isCameraInitialized = true;
    snapFrames = 60; // Принудительно держим камеру на игроке 60 кадров (1 секунду)
}

export function adjustZoom(deltaY: number) {
    cameraZoom -= deltaY * 0.001;
    if (cameraZoom < 0.8) cameraZoom = 0.8;
    if (cameraZoom > 3.0) cameraZoom = 3.0;
}

function getAnimationFrame(isMoving: boolean, isSprinting: boolean): AnimFrame {
    if (!isMoving) return 0;
    const frameDuration = isSprinting ? 75 : 150;
    const now = Date.now();
    const cycle = Math.floor(now / frameDuration) % 4;
    return (cycle === 3) ? 2 : (cycle as AnimFrame);
}

export function drawCharacterPreview(ctxPreview: CanvasRenderingContext2D, player: Player) {
    const w = ctxPreview.canvas.width; const h = ctxPreview.canvas.height;
    ctxPreview.clearRect(0, 0, w, h); ctxPreview.save(); ctxPreview.translate(w/2, h/2); ctxPreview.scale(1.2, 1.2); ctxPreview.translate(-32, -42); 

    // Выбираем спрайт по цвету игрока
    const baseKey = `base_${player.color}`;
    const baseSprite = (charSprites[baseKey] && charSprites[baseKey][0]) ? charSprites[baseKey][0] : (charSprites['base_#FFFFFF'] ? charSprites['base_#FFFFFF'][0] : charSprites['base'][0]);

    if (baseSprite) ctxPreview.drawImage(baseSprite, 0, 0, 64, 84);

    if (player.equipment.legs && charSprites[player.equipment.legs]) ctxPreview.drawImage(charSprites[player.equipment.legs][0], 0, 0, 64, 84);
    if (player.equipment.body && charSprites[player.equipment.body]) ctxPreview.drawImage(charSprites[player.equipment.body][0], 0, 0, 64, 84);
    if (player.equipment.head && charSprites[player.equipment.head]) ctxPreview.drawImage(charSprites[player.equipment.head][0], 0, 0, 64, 84);
    ctxPreview.restore();
}

function drawPlayer(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean, isMoving: boolean, isSprinting: boolean) {
    const isInWater = isPositionInWater(player.x, player.y);
    const x = player.x; let y = player.y;
    if (isInWater) y += 5 + Math.sin(Date.now() / 400) * 2; 
    const frame = getAnimationFrame(isMoving, isSprinting);
    const dir = player.direction || 'front';
    const isFlipped = dir === 'right';
    ctx.save(); ctx.translate(x, y);
    if (!isLocal) {
        ctx.fillStyle = '#FFFFFF'; ctx.shadowColor = 'black'; ctx.shadowBlur = 4; ctx.font = 'bold 12px sans-serif'; ctx.textAlign = 'center'; ctx.fillText(player.nickname, 0, -55); ctx.shadowBlur = 0;
    }
    if (!isInWater) { ctx.fillStyle = 'rgba(0,0,0,0.25)'; ctx.beginPath(); ctx.ellipse(0, 12, 16, 6, 0, 0, Math.PI*2); ctx.fill(); }
    else {
        const ripple = (Math.sin(Date.now() / 500) + 1) / 2;
        ctx.strokeStyle = `rgba(255, 255, 255, ${0.4 - ripple * 0.2})`; ctx.lineWidth = 2; ctx.beginPath(); ctx.ellipse(0, 0, 12 + ripple * 4, 6 + ripple * 2, 0, 0, Math.PI*2); ctx.stroke();
    }
    if (isFlipped) ctx.scale(-1, 1);
    if (isInWater) { ctx.beginPath(); ctx.rect(-40, -100, 80, 100); ctx.clip(); }
    ctx.translate(-32, -60); 

    // Выбираем правильный спрайт базы на основе цвета игрока
    const baseKey = `base_${player.color}`;
    // Fallback: если цвет не найден (например, старый кеш), берем белый
    const baseSpriteSet = charSprites[baseKey] || charSprites['base_#FFFFFF'] || charSprites['base'];

    if (baseSpriteSet && baseSpriteSet[frame]) ctx.drawImage(baseSpriteSet[frame], 0, 0, 64, 84);

    if (player.equipment) {
        if (player.equipment.legs && charSprites[player.equipment.legs]) ctx.drawImage(charSprites[player.equipment.legs][frame], 0, 0, 64, 84);
        if (player.equipment.body && charSprites[player.equipment.body]) ctx.drawImage(charSprites[player.equipment.body][frame], 0, 0, 64, 84);
        if (player.equipment.head && charSprites[player.equipment.head]) ctx.drawImage(charSprites[player.equipment.head][frame], 0, 0, 64, 84);
    }
    if (isLocal) {
        const item = getSelectedItem();
        if (item) {
            ctx.font = '24px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; 

            // Если персонаж развернут, нужно развернуть текст обратно,
            // но при этом скорректировать координату X, так как система координат смещена
            if (isFlipped) {
                ctx.scale(-1, 1);
                // В развернутой системе координат центр спрайта смещается
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, -32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            } else {
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, 32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            }
        }
    }
    ctx.restore();
}

interface RenderObject { y: number; type: string; data: any; }

function lerp(start: number, end: number, t: number) { return start * (1 - t) + end * t; }

export function renderGame(miningProgress: number = 0, targetX: number = 0, targetY: number = 0, isSprinting: boolean = false) {
  if (!ctx || !canvas) return;
  const me = gameState.players[gameState.localPlayerId];
  if (!me) return;

  // Инициализация, если камера еще не была настроена
  if (!isCameraInitialized) {
      camX = me.x;
      camY = me.y;
      isCameraInitialized = true;
      snapFrames = 60; // Включаем режим фиксации
  }

  // Принудительная фиксация камеры в первые моменты игры
  if (snapFrames > 0) {
      camX = me.x;
      camY = me.y;
      snapFrames--;
  } else {
      // Стандартное плавное слежение
      // Если дистанция слишком большая (телепорт, респавн), прыгаем сразу
      const dist = Math.sqrt((camX - me.x)**2 + (camY - me.y)**2);
      if (dist > 500) { 
          camX = me.x; 
          camY = me.y; 
      } else {
          const lerpFactor = isSprinting ? 0.08 : 0.15;
          camX = lerp(camX, me.x, lerpFactor); 
          camY = lerp(camY, me.y, lerpFactor);
      }
  }

  // Защита от NaN
  if (isNaN(camX)) camX = me.x;
  if (isNaN(camY)) camY = me.y;

  const dpr = window.devicePixelRatio || 1;

  // ФОН: Если тестовый мир - белый/серый, иначе зеленый
  ctx.fillStyle = gameState.useTestWorld ? '#e2e8f0' : '#4e8c33'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  ctx.save();
  ctx.scale(dpr, dpr);
  // Используем размеры канваса для точного центрирования
  const logicalWidth = canvas.width / dpr; 
  const logicalHeight = canvas.height / dpr;

  ctx.translate(Math.floor(logicalWidth / 2), Math.floor(logicalHeight / 2));
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-Math.floor(camX), -Math.floor(camY)); // Округляем для четкости пикселей

  const viewW = logicalWidth / cameraZoom, viewH = logicalHeight / cameraZoom;
  const startTileX = Math.floor((camX - viewW/2) / TILE_SIZE) - 1;
  const endTileX = Math.floor((camX + viewW/2) / TILE_SIZE) + 2;
  const startTileY = Math.floor((camY - viewH/2) / TILE_SIZE) - 2; 
  const endTileY = Math.floor((camY + viewH/2) / TILE_SIZE) + 4;

  const renderList: RenderObject[] = [];

  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const screenX = x * TILE_SIZE, screenY = y * TILE_SIZE;
        const tileData = getTileData(x, y);

        // РЕНДЕРИНГ ПОВЕРХНОСТИ
        if (tileData.terrain === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            // --- ЛОГИКА БЕРЕГОВ (СКРУГЛЕНИЯ) ---
            const isN = getTileData(x, y - 1).terrain === 'grass';
            const isS = getTileData(x, y + 1).terrain === 'grass';
            const isW = getTileData(x - 1, y).terrain === 'grass';
            const isE = getTileData(x + 1, y).terrain === 'grass';

            if (isN && isW) ctx.drawImage(textures['mask_corner_tl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isN && isE) ctx.drawImage(textures['mask_corner_tr'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isW) ctx.drawImage(textures['mask_corner_bl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isE) ctx.drawImage(textures['mask_corner_br'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            const waveHash = Math.sin(x * 12.9898 + y * 78.233) * 43758.5453;
            if ((waveHash - Math.floor(waveHash)) > 0.85) ctx.drawImage(textures['water_wave'], screenX, screenY + Math.sin(Date.now() / 500) * 2, TILE_SIZE, TILE_SIZE);
        } else if (!gameState.useTestWorld) {
            ctx.drawImage(textures['grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.floor === 'wood') ctx.drawImage(textures['floor_wood'], screenX, screenY, TILE_SIZE, TILE_SIZE);

        if (gameState.showDebugGrid || gameState.useTestWorld) {
            ctx.strokeStyle = gameState.useTestWorld ? 'rgba(0,0,0,0.05)' : 'rgba(255,255,255,0.1)'; 
            ctx.strokeRect(screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.object === 'tree') renderList.push({ y: screenY + 35, type: 'tree', data: { x: screenX - 50, y: screenY - 180 } });
        else if (tileData.object === 'stone') renderList.push({ y: screenY + 30, type: 'stone', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'big_rock') renderList.push({ y: screenY + 38, type: 'big_rock', data: { x: screenX - 30, y: screenY - 40 } });
        else if (tileData.object === 'workbench') renderList.push({ y: screenY + 30, type: 'workbench', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'high_grass') ctx.drawImage(textures['high_grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        else if (tileData.object.startsWith('wall_wood') || tileData.object.startsWith('door_wood')) {
             let sortY = screenY + TILE_SIZE; if (tileData.object.includes('_t')) sortY = screenY + 10;
             let angle = 0; if (tileData.object.startsWith('door_wood')) { const k = `${x},${y}`; if (gameState.doorStates[k]) angle = gameState.doorStates[k].angle; }
             renderList.push({ y: sortY, type: tileData.object.startsWith('door_wood') ? 'door' : 'wall', data: { x: screenX, y: screenY, tex: textures[tileData.object], angle, subType: tileData.object.split('_').pop() } });
        }
        tileData.items.forEach((item, i) => {
            const seed = x * 1000 + y + i * 50;
            renderList.push({ y: screenY + TILE_SIZE/2, type: 'ground_item', data: { x: screenX + TILE_SIZE/2 + Math.sin(seed)*10, y: screenY + TILE_SIZE/2 + Math.cos(seed)*10, type: item, rotation: Math.sin(seed*0.1)*Math.PI } });
        });
    }
  }
  for (const id in gameState.players) renderList.push({ y: gameState.players[id].y + 12, type: 'player', data: { player: gameState.players[id], isLocal: id === gameState.localPlayerId, isMoving: id === gameState.localPlayerId ? (window as any).isLocalMoving : false, isSprinting: id === gameState.localPlayerId ? isSprinting : false } });
  renderList.sort((a, b) => a.y - b.y);

  for (const obj of renderList) {
      if (obj.type === 'tree') {
          const dist = Math.sqrt((me.x - (obj.data.x + 70))**2 + (me.y - (obj.data.y + 110))**2);
          ctx.drawImage(textures['tree_trunk'], obj.data.x, obj.data.y, 140, 220);
          if (dist < 220 && me.y < obj.y) ctx.globalAlpha = 0.4;
          ctx.drawImage(textures['tree_canopy'], obj.data.x, obj.data.y, 140, 220); ctx.globalAlpha = 1.0; 
      } else if (obj.type === 'stone') ctx.drawImage(textures['stone'], obj.data.x - 10, obj.data.y - 10, TILE_SIZE*1.5, TILE_SIZE*1.5);
      else if (obj.type === 'big_rock') ctx.drawImage(textures['big_rock'], obj.data.x, obj.data.y, 100, 80);
      else if (obj.type === 'wall') ctx.drawImage(obj.data.tex, obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'door') {
          ctx.save(); const { x, y, angle, subType } = obj.data;
          // Убран минус перед углом для типов 'b' и 'r', чтобы они открывались в правильную сторону от игрока
          if (subType === 't') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'b') { ctx.translate(x, y + TILE_SIZE); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, -TILE_SIZE, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'l') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'r') { ctx.translate(x + TILE_SIZE, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, -TILE_SIZE, 0, TILE_SIZE, TILE_SIZE); }
          ctx.restore();
      } else if (obj.type === 'workbench') ctx.drawImage(textures['workbench'], obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'player') drawPlayer(ctx, obj.data.player, obj.data.isLocal, obj.data.isMoving, obj.data.isSprinting);
      else if (obj.type === 'ground_item') {
          const item = obj.data; ctx.save(); ctx.translate(item.x, item.y); ctx.rotate(item.rotation);
          const tex = (item.type === 'stick' || item.type === 'wood') ? textures['ground_twig'] : textures['ground_pebble'];
          if (tex) { const w = (item.type === 'stick' || item.type === 'wood') ? 32 : 16; ctx.drawImage(tex, -w/2, -w/2, w, w); }
          ctx.restore();
      }
  }

  // --- DAY/NIGHT OVERLAY ---
  ctx.restore(); // Выходим из мировых координат для полноэкранного фильтра
  ctx.save();
  const time = gameState.worldTime;
  let nightAlpha = 0;
  if (!gameState.useTestWorld && time > 14000 && time < 22000) { // В тестовом мире всегда день
      if (time < 18000) nightAlpha = (time - 14000) / 4000;
      else nightAlpha = 1 - (time - 18000) / 4000;
  }
  if (nightAlpha > 0) {
      const maxNight = 0.65;
      ctx.fillStyle = `rgba(10, 10, 40, ${nightAlpha * maxNight})`;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Легкое свечение вокруг игрока
      const gradient = ctx.createRadialGradient(logicalWidth/2, logicalHeight/2, 0, logicalWidth/2, logicalHeight/2, 200);
      gradient.addColorStop(0, 'rgba(255, 255, 200, 0.15)');
      gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.globalCompositeOperation = 'destination-out';
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.globalCompositeOperation = 'source-over';
  }
  ctx.restore();

  // Возвращаемся в мировые координаты для UI элементов над миром (прогресс добычи и т.д.)
  ctx.save();
  ctx.scale(dpr, dpr);
  ctx.translate(Math.floor(logicalWidth / 2), Math.floor(logicalHeight / 2));
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-Math.floor(camX), -Math.floor(camY));

  if (miningProgress > 0) {
      const worldX = targetX * TILE_SIZE + TILE_SIZE / 2, worldY = targetY * TILE_SIZE; 
      ctx.fillStyle = 'rgba(0,0,0,0.5)'; ctx.fillRect(worldX - 20, worldY - 15, 40, 6);
      ctx.fillStyle = '#4ade80'; ctx.fillRect(worldX - 20 + 1, worldY - 14, 38 * miningProgress, 4);
  }
  for (let i = floatingTexts.length - 1; i >= 0; i--) {
      const ft = floatingTexts[i]; ft.life--; ft.y -= 0.5; ctx.globalAlpha = ft.life / ft.maxLife;
      ctx.font = 'bold 16px sans-serif'; ctx.textAlign = 'center'; ctx.strokeStyle = 'black'; ctx.lineWidth = 3; ctx.strokeText(ft.text, ft.x, ft.y); ctx.fillStyle = ft.color; ctx.fillText(ft.text, ft.x, ft.y);
      ctx.globalAlpha = 1.0; if (ft.life <= 0) floatingTexts.splice(i, 1);
  }
  ctx.restore(); 
}

// index.tsx: Главная точка входа
import { Players, Player, Direction } from './types';
import { TILE_SIZE } from './constants';
import { initInput, inputState } from './input';

// Modules
import { gameState, setPlayers, setLocalPlayerId, getLocalPlayer } from './state';
import { initRenderer, renderGame, adjustZoom, getCameraZoom, addFloatingText, resetCamera } from './renderer';
import { generateAssets } from './assets';
import { initWorld, applyWorldUpdate, canMoveTo, isPositionInWater } from './world';
import { updateDoorPhysics } from './physics'; 
import { initInventory, syncInventoryWithServer, toggleInventory, handleHotbarKey, resetInventory, isInventoryOpen, getSelectedItem, cycleHotbar } from './inventory';
import { initUI, showGameScreen, updateOnlineCount, updateRoomList } from './ui';
import { initNetwork, emitMovement } from './network';
import { isChatOpen, toggleChat, addChatMessage } from './chat';
import { handleInteraction, currentMiningProgress, currentMiningTargetX, currentMiningTargetY, placementRotation, setPlacementRotation } from './interaction';
import { PLAYER_COLORS } from './assetHuman';

const canvas = document.getElementById('game-canvas') as HTMLCanvasElement;
const gameContainer = document.getElementById('game-container') as HTMLDivElement;

const hudEls = {
    hp: document.getElementById('bar-hp-fill'),
    hunger: document.getElementById('bar-hunger-fill'),
    mana: document.getElementById('bar-mana-fill'),
    energy: document.getElementById('bar-energy-fill'),
    xp: document.getElementById('bar-xp-fill'),
    level: document.getElementById('level-val'),
    textHp: document.getElementById('text-hp'),
    textHunger: document.getElementById('text-hunger'),
    textMana: document.getElementById('text-mana'),
    textEnergy: document.getElementById('text-energy')
};

const BASE_WALK_SPEED = 3;
const BASE_SPRINT_SPEED = 6;
let fps = 0;
let lastLoop = 0;
let isGameRunning = false;
const fpsEl = document.getElementById('fps-counter');
let lastRotateTime = 0;

document.addEventListener('DOMContentLoaded', () => {
    initRenderer(canvas);
    generateAssets();
    initInventory();

    // Сразу устанавливаем размеры канваса, чтобы избежать проблем с координатами
    resizeCanvas();

    const movement = initInput(canvas);

    initUI({ onStartOffline: startGameOffline });

    initNetwork({
        onConnect: (id) => setLocalPlayerId(id),
        onOnlineCount: updateOnlineCount,
        onRoomList: updateRoomList,
        onGameStart: (players, worldChanges, seed) => {
            gameState.isOffline = false;
            if (seed) gameState.worldSeed = seed;
            if (worldChanges) worldChanges.forEach(update => applyWorldUpdate(update));
            startGame(players, gameState.localPlayerId);
            addChatMessage("SYSTEM", `Welcome to Terra Wilds! Seed: ${gameState.worldSeed}`, "#fbbf24", true);
        },
        onState: (serverPlayers, serverTime) => {
            const me = getLocalPlayer();
            const serverMe = serverPlayers[gameState.localPlayerId];

            // Синхронизация времени с сервера
            if (typeof serverTime === 'number') {
                gameState.worldTime = serverTime;
            }

            if (me && serverMe) {
                if (serverMe.inventory) syncInventoryWithServer(serverMe.inventory);
                if (serverMe.stats) {
                    me.stats.hp = serverMe.stats.hp;
                    me.stats.maxHp = serverMe.stats.maxHp;
                    me.stats.hunger = serverMe.stats.hunger;
                    me.stats.xp = serverMe.stats.xp;
                    me.stats.level = serverMe.stats.level;
                    if (Math.abs(me.stats.energy - serverMe.stats.energy) > 5) me.stats.energy = serverMe.stats.energy;
                }
                const dist = Math.sqrt(Math.pow(me.x - serverMe.x, 2) + Math.pow(me.y - serverMe.y, 2));
                if (dist > 150) { me.x = serverMe.x; me.y = serverMe.y; }
                else serverPlayers[gameState.localPlayerId] = me;
            }
            setPlayers(serverPlayers);
        },
        onWorldUpdate: (update) => applyWorldUpdate(update),
        onError: (msg) => alert(`Ошибка: ${msg}`),
        onDebugLog: (msg) => console.error(msg),
        onChatMessage: (data) => addChatMessage(data.nickname, data.text, data.color)
    });

    window.addEventListener('resize', resizeCanvas);
    canvas.addEventListener('wheel', (e) => {
        if (!gameContainer.classList.contains('hidden')) { e.preventDefault(); adjustZoom(e.deltaY); }
    }, { passive: false });

    window.addEventListener('keydown', (e) => {
        const startScreen = document.getElementById('start-screen');
        if (startScreen && startScreen.classList.contains('hidden')) {
            if (!isChatOpen && (e.code === 'Enter' || e.code === 'KeyT')) { e.preventDefault(); toggleChat(true); return; }
            if (e.code === 'Escape') { if (isChatOpen) toggleChat(false); else if (isInventoryOpen) toggleInventory(); return; }
            if (isChatOpen) return;
            if (e.code === 'Tab') { e.preventDefault(); toggleInventory(); }
            if (e.code === 'KeyQ') cycleHotbar(-1);
            if (e.code === 'KeyE') cycleHotbar(1);
            if (e.key >= '1' && e.key <= '9') handleHotbarKey(parseInt(e.key) - 1);
        }
    });

    function resizeCanvas() { 
        const dpr = window.devicePixelRatio || 1;
        // Округляем до целых для избежания субпиксельных артефактов
        const w = Math.floor(window.innerWidth * dpr);
        const h = Math.floor(window.innerHeight * dpr);

        // Обновляем только если размеры изменились
        if (canvas.width !== w || canvas.height !== h) {
            canvas.width = w; 
            canvas.height = h;
            canvas.style.width = window.innerWidth + 'px'; 
            canvas.style.height = window.innerHeight + 'px';
            const ctx = canvas.getContext('2d');
            if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
        }
    }

    function startGame(initialPlayers: Players, playerId: string) {
        setPlayers(initialPlayers);
        setLocalPlayerId(playerId);
        resetInventory();
        const me = initialPlayers[playerId];
        if (me && me.inventory) syncInventoryWithServer(me.inventory);
        initWorld(me.x, me.y);
        showGameScreen();
        resizeCanvas();
        resetCamera(me.x, me.y); // Центрируем камеру на старте (включит snapFrames)
        if (fpsEl) fpsEl.classList.remove('hidden');

        // Запускаем цикл только если он еще не запущен
        if (!isGameRunning) {
            isGameRunning = true;
            gameLoop();
        }
    }

    function startGameOffline() {
        const pid = 'offline_hero';
        if (!gameState.worldSeed || gameState.worldSeed === 'terrawilds') gameState.worldSeed = Math.floor(Math.random() * 1999999999 - 999999999).toString();
        const player: Player = {
            id: pid, x: 0, y: 0, 
            color: PLAYER_COLORS[Math.floor(Math.random() * PLAYER_COLORS.length)], 
            nickname: "Explorer", direction: 'front',
            inventory: [], equipment: { head: null, body: null, legs: null },
            stats: { hp: 20, maxHp: 20, hunger: 20, maxHunger: 20, mana: 20, maxMana: 20, energy: 20, maxEnergy: 20, xp: 0, maxXp: 100, level: 1 }
        };
        startGame({ [pid]: player }, pid);
        if (gameState.useTestWorld) {
            const debugPanel = document.getElementById('debug-panel');
            if (debugPanel) debugPanel.style.display = 'block';
            addChatMessage("DEV", "ТЕСТОВЫЙ МИР: Бесконечные ресурсы и респавн включены.", "#60a5fa", true);
        } else {
            addChatMessage("AI", "Мир готов! Смена дня и ночи запущена. Загляни в дебаг-меню (/debug) для управления временем!", "#10b981");
        }
    }

    function gameLoop() {
        if (gameContainer.classList.contains('hidden')) {
            isGameRunning = false;
            return;
        }

        // Легковесная проверка изменения размера окна (например, на мобильных при скрытии адресной строки)
        const dpr = window.devicePixelRatio || 1;
        if (Math.abs(canvas.width - window.innerWidth * dpr) > 10) {
            resizeCanvas();
        }

        const now = performance.now();
        const delta = now - lastLoop;
        lastLoop = now;

        // Продвижение времени (только в офлайне, в онлайне берем с сервера)
        if (gameState.isOffline && !gameState.isTimePaused) {
            gameState.worldTime = (gameState.worldTime + 5) % 24000;
        }

        const me = getLocalPlayer();
        if (me) {
            if (movement.rotate && now - lastRotateTime > 200) { setPlacementRotation((placementRotation + 1) % 4); lastRotateTime = now; }
            handleInteraction(me);
            updateDoorPhysics(); 
            let canSprint = false; let currentSpeed = BASE_WALK_SPEED; let dx = 0, dy = 0; let newDir: Direction = me.direction;
            if (!isChatOpen) {
                if (me.stats) {
                    if (movement.sprint && me.stats.energy > 0) { canSprint = true; me.stats.energy -= 0.15; }
                    else if (!movement.sprint && me.stats.energy < me.stats.maxEnergy) me.stats.energy += 0.1;
                }
                currentSpeed = (canSprint ? BASE_SPRINT_SPEED : BASE_WALK_SPEED) * gameState.debug.speedMult;
                if (isPositionInWater(me.x, me.y)) currentSpeed *= 0.5;
                if (movement.up) { dy -= currentSpeed; newDir = 'back'; }
                if (movement.down) { dy += currentSpeed; newDir = 'front'; }
                if (movement.left) { dx -= currentSpeed; newDir = 'left'; }
                if (movement.right) { dx += currentSpeed; newDir = 'right'; }
            }
            if (dx !== 0 || dy !== 0) { 
                me.direction = newDir; (window as any).isLocalMoving = true; 
                if (dx !== 0 && canMoveTo(me.x + dx, me.y, 32, 32)) me.x += dx;
                if (dy !== 0 && canMoveTo(me.x, me.y + dy, 32, 32)) me.y += dy;
            } else (window as any).isLocalMoving = false;
            if (!gameState.isOffline) emitMovement({ x: me.x, y: me.y, direction: me.direction, sprint: canSprint });
            if (me.stats && hudEls.hp) {
                hudEls.hp.style.width = `${(me.stats.hp / me.stats.maxHp) * 100}%`;
                hudEls.hunger!.style.width = `${(me.stats.hunger / me.stats.maxHunger) * 100}%`;
                hudEls.mana!.style.width = `${(me.stats.mana / me.stats.maxMana) * 100}%`;
                hudEls.energy!.style.width = `${(me.stats.energy / me.stats.maxEnergy) * 100}%`;
                hudEls.xp!.style.width = `${(me.stats.xp / me.stats.maxXp) * 100}%`;
                hudEls.textHp!.textContent = String(Math.floor(me.stats.hp));
                hudEls.textHunger!.textContent = String(Math.floor(me.stats.hunger));
                hudEls.textEnergy!.textContent = String(Math.floor(me.stats.energy));
                hudEls.level!.textContent = String(me.stats.level);
            }
        }
        renderGame(currentMiningProgress, currentMiningTargetX, currentMiningTargetY, !isChatOpen && movement.sprint && me?.stats && me.stats.energy > 0);
        requestAnimationFrame(gameLoop);
    }
});

// renderer.ts: Отрисовка игрового мира и сущностей
import { TILE_SIZE } from './constants';
import { Player } from './types';
import { gameState } from './state';
import { textures, charSprites, AnimFrame } from './assets';
import { getTileData, isPositionInWater, canPlaceObject, getInteractionType } from './world';
import { getSelectedItem } from './inventory';
import { inputState } from './input';
import { placementRotation } from './interaction'; 

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;
export let cameraZoom = 1.5; 

let camX = 0;
let camY = 0;
let isCameraInitialized = false;
let snapFrames = 0; // Счетчик кадров для принудительной центровки

interface FloatingText {
    x: number; y: number; text: string; life: number; maxLife: number; color: string;
}
const floatingTexts: FloatingText[] = [];

export function addFloatingText(x: number, y: number, text: string, color: string = '#ffffff') {
    floatingTexts.push({ x, y, text, life: 60, maxLife: 60, color });
}

export function getCameraZoom() { return cameraZoom; }

export function initRenderer(canvasEl: HTMLCanvasElement) {
    canvas = canvasEl; ctx = canvas.getContext('2d');
    if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
}

export function resetCamera(x: number, y: number) {
    camX = x;
    camY = y;
    isCameraInitialized = true;
    snapFrames = 120; // 2 секунды (при 60fps) жесткой привязки
}

export function adjustZoom(deltaY: number) {
    cameraZoom -= deltaY * 0.001;
    if (cameraZoom < 0.8) cameraZoom = 0.8;
    if (cameraZoom > 3.0) cameraZoom = 3.0;
}

function getAnimationFrame(isMoving: boolean, isSprinting: boolean): AnimFrame {
    if (!isMoving) return 0;
    const frameDuration = isSprinting ? 75 : 150;
    const now = Date.now();
    const cycle = Math.floor(now / frameDuration) % 4;
    return (cycle === 3) ? 2 : (cycle as AnimFrame);
}

export function drawCharacterPreview(ctxPreview: CanvasRenderingContext2D, player: Player) {
    const w = ctxPreview.canvas.width; const h = ctxPreview.canvas.height;
    ctxPreview.clearRect(0, 0, w, h); ctxPreview.save(); ctxPreview.translate(w/2, h/2); ctxPreview.scale(1.2, 1.2); ctxPreview.translate(-32, -42); 

    // Выбираем спрайт по цвету игрока
    const baseKey = `base_${player.color}`;
    const baseSprite = (charSprites[baseKey] && charSprites[baseKey][0]) ? charSprites[baseKey][0] : (charSprites['base_#FFFFFF'] ? charSprites['base_#FFFFFF'][0] : charSprites['base'][0]);

    if (baseSprite) ctxPreview.drawImage(baseSprite, 0, 0, 64, 84);

    if (player.equipment.legs && charSprites[player.equipment.legs]) ctxPreview.drawImage(charSprites[player.equipment.legs][0], 0, 0, 64, 84);
    if (player.equipment.body && charSprites[player.equipment.body]) ctxPreview.drawImage(charSprites[player.equipment.body][0], 0, 0, 64, 84);
    if (player.equipment.head && charSprites[player.equipment.head]) ctxPreview.drawImage(charSprites[player.equipment.head][0], 0, 0, 64, 84);
    ctxPreview.restore();
}

function drawPlayer(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean, isMoving: boolean, isSprinting: boolean) {
    const isInWater = isPositionInWater(player.x, player.y);
    const x = player.x; let y = player.y;
    if (isInWater) y += 5 + Math.sin(Date.now() / 400) * 2; 
    const frame = getAnimationFrame(isMoving, isSprinting);
    const dir = player.direction || 'front';
    const isFlipped = dir === 'right';
    ctx.save(); ctx.translate(x, y);
    if (!isLocal) {
        ctx.fillStyle = '#FFFFFF'; ctx.shadowColor = 'black'; ctx.shadowBlur = 4; ctx.font = 'bold 12px sans-serif'; ctx.textAlign = 'center'; ctx.fillText(player.nickname, 0, -55); ctx.shadowBlur = 0;
    }
    if (!isInWater) { ctx.fillStyle = 'rgba(0,0,0,0.25)'; ctx.beginPath(); ctx.ellipse(0, 12, 16, 6, 0, 0, Math.PI*2); ctx.fill(); }
    else {
        const ripple = (Math.sin(Date.now() / 500) + 1) / 2;
        ctx.strokeStyle = `rgba(255, 255, 255, ${0.4 - ripple * 0.2})`; ctx.lineWidth = 2; ctx.beginPath(); ctx.ellipse(0, 0, 12 + ripple * 4, 6 + ripple * 2, 0, 0, Math.PI*2); ctx.stroke();
    }
    if (isFlipped) ctx.scale(-1, 1);
    if (isInWater) { ctx.beginPath(); ctx.rect(-40, -100, 80, 100); ctx.clip(); }
    ctx.translate(-32, -60); 

    // Выбираем правильный спрайт базы на основе цвета игрока
    const baseKey = `base_${player.color}`;
    // Fallback: если цвет не найден (например, старый кеш), берем белый
    const baseSpriteSet = charSprites[baseKey] || charSprites['base_#FFFFFF'] || charSprites['base'];

    if (baseSpriteSet && baseSpriteSet[frame]) ctx.drawImage(baseSpriteSet[frame], 0, 0, 64, 84);

    if (player.equipment) {
        if (player.equipment.legs && charSprites[player.equipment.legs]) ctx.drawImage(charSprites[player.equipment.legs][frame], 0, 0, 64, 84);
        if (player.equipment.body && charSprites[player.equipment.body]) ctx.drawImage(charSprites[player.equipment.body][frame], 0, 0, 64, 84);
        if (player.equipment.head && charSprites[player.equipment.head]) ctx.drawImage(charSprites[player.equipment.head][frame], 0, 0, 64, 84);
    }
    if (isLocal) {
        const item = getSelectedItem();
        if (item) {
            ctx.font = '24px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; 

            // Если персонаж развернут, нужно развернуть текст обратно,
            // но при этом скорректировать координату X, так как система координат смещена
            if (isFlipped) {
                ctx.scale(-1, 1);
                // В развернутой системе координат центр спрайта смещается
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, -32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            } else {
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, 32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            }
        }
    }
    ctx.restore();
}

interface RenderObject { y: number; type: string; data: any; }

function lerp(start: number, end: number, t: number) { return start * (1 - t) + end * t; }

export function renderGame(miningProgress: number = 0, targetX: number = 0, targetY: number = 0, isSprinting: boolean = false) {
  if (!ctx || !canvas) return;
  const me = gameState.players[gameState.localPlayerId];
  if (!me) return;

  // --- ЛОГИКА КАМЕРЫ (АГРЕССИВНАЯ) ---

  // Если камера не инициализирована или идет фаза "приклеивания" (snapFrames > 0)
  if (!isCameraInitialized || snapFrames > 0) {
      camX = me.x;
      camY = me.y;
      isCameraInitialized = true;
      if (snapFrames > 0) snapFrames--;
  } else {
      // Проверка дистанции: если игрок слишком далеко (например, телепорт или лаг) - мгновенный прыжок
      // 300 пикселей - это чуть меньше половины экрана по вертикали, надежный порог
      const dist = Math.sqrt((camX - me.x)**2 + (camY - me.y)**2);

      // Защита от "нулевого бага": если камера в 0,0, а игрок далеко - прыгаем
      const isZeroBug = (Math.abs(camX) < 1 && Math.abs(camY) < 1 && (Math.abs(me.x) > 50 || Math.abs(me.y) > 50));

      if (dist > 300 || isZeroBug) { 
          camX = me.x; 
          camY = me.y; 
      } else {
          // Иначе плавное слежение
          const lerpFactor = isSprinting ? 0.1 : 0.15; // Чуть быстрее для спринта
          camX = lerp(camX, me.x, lerpFactor); 
          camY = lerp(camY, me.y, lerpFactor);
      }
  }

  // Защита от NaN (если координаты игрока пришли битые)
  if (isNaN(camX)) camX = me.x;
  if (isNaN(camY)) camY = me.y;

  const dpr = window.devicePixelRatio || 1;

  // ФОН: Если тестовый мир - белый/серый, иначе зеленый
  ctx.fillStyle = gameState.useTestWorld ? '#e2e8f0' : '#4e8c33'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  ctx.save();
  ctx.scale(dpr, dpr);
  // Используем размеры канваса для точного центрирования
  const logicalWidth = canvas.width / dpr; 
  const logicalHeight = canvas.height / dpr;

  ctx.translate(Math.floor(logicalWidth / 2), Math.floor(logicalHeight / 2));
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-Math.floor(camX), -Math.floor(camY)); // Округляем для четкости пикселей

  const viewW = logicalWidth / cameraZoom, viewH = logicalHeight / cameraZoom;
  const startTileX = Math.floor((camX - viewW/2) / TILE_SIZE) - 1;
  const endTileX = Math.floor((camX + viewW/2) / TILE_SIZE) + 2;
  const startTileY = Math.floor((camY - viewH/2) / TILE_SIZE) - 2; 
  const endTileY = Math.floor((camY + viewH/2) / TILE_SIZE) + 4;

  const renderList: RenderObject[] = [];

  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const screenX = x * TILE_SIZE, screenY = y * TILE_SIZE;
        const tileData = getTileData(x, y);

        // РЕНДЕРИНГ ПОВЕРХНОСТИ
        if (tileData.terrain === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            // --- ЛОГИКА БЕРЕГОВ (СКРУГЛЕНИЯ) ---
            const isN = getTileData(x, y - 1).terrain === 'grass';
            const isS = getTileData(x, y + 1).terrain === 'grass';
            const isW = getTileData(x - 1, y).terrain === 'grass';
            const isE = getTileData(x + 1, y).terrain === 'grass';

            if (isN && isW) ctx.drawImage(textures['mask_corner_tl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isN && isE) ctx.drawImage(textures['mask_corner_tr'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isW) ctx.drawImage(textures['mask_corner_bl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isE) ctx.drawImage(textures['mask_corner_br'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            const waveHash = Math.sin(x * 12.9898 + y * 78.233) * 43758.5453;
            if ((waveHash - Math.floor(waveHash)) > 0.85) ctx.drawImage(textures['water_wave'], screenX, screenY + Math.sin(Date.now() / 500) * 2, TILE_SIZE, TILE_SIZE);
        } else if (!gameState.useTestWorld) {
            ctx.drawImage(textures['grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.floor === 'wood') ctx.drawImage(textures['floor_wood'], screenX, screenY, TILE_SIZE, TILE_SIZE);

        if (gameState.showDebugGrid || gameState.useTestWorld) {
            ctx.strokeStyle = gameState.useTestWorld ? 'rgba(0,0,0,0.05)' : 'rgba(255,255,255,0.1)'; 
            ctx.strokeRect(screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.object === 'tree') renderList.push({ y: screenY + 35, type: 'tree', data: { x: screenX - 50, y: screenY - 180 } });
        else if (tileData.object === 'stone') renderList.push({ y: screenY + 30, type: 'stone', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'big_rock') renderList.push({ y: screenY + 38, type: 'big_rock', data: { x: screenX - 30, y: screenY - 40 } });
        else if (tileData.object === 'workbench') renderList.push({ y: screenY + 30, type: 'workbench', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'high_grass') ctx.drawImage(textures['high_grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        else if (tileData.object.startsWith('wall_wood') || tileData.object.startsWith('door_wood')) {
             let sortY = screenY + TILE_SIZE; if (tileData.object.includes('_t')) sortY = screenY + 10;
             let angle = 0; if (tileData.object.startsWith('door_wood')) { const k = `${x},${y}`; if (gameState.doorStates[k]) angle = gameState.doorStates[k].angle; }
             renderList.push({ y: sortY, type: tileData.object.startsWith('door_wood') ? 'door' : 'wall', data: { x: screenX, y: screenY, tex: textures[tileData.object], angle, subType: tileData.object.split('_').pop() } });
        }
        tileData.items.forEach((item, i) => {
            const seed = x * 1000 + y + i * 50;
            renderList.push({ y: screenY + TILE_SIZE/2, type: 'ground_item', data: { x: screenX + TILE_SIZE/2 + Math.sin(seed)*10, y: screenY + TILE_SIZE/2 + Math.cos(seed)*10, type: item, rotation: Math.sin(seed*0.1)*Math.PI } });
        });
    }
  }
  for (const id in gameState.players) renderList.push({ y: gameState.players[id].y + 12, type: 'player', data: { player: gameState.players[id], isLocal: id === gameState.localPlayerId, isMoving: id === gameState.localPlayerId ? (window as any).isLocalMoving : false, isSprinting: id === gameState.localPlayerId ? isSprinting : false } });
  renderList.sort((a, b) => a.y - b.y);

  for (const obj of renderList) {
      if (obj.type === 'tree') {
          const dist = Math.sqrt((me.x - (obj.data.x + 70))**2 + (me.y - (obj.data.y + 110))**2);
          ctx.drawImage(textures['tree_trunk'], obj.data.x, obj.data.y, 140, 220);
          if (dist < 220 && me.y < obj.y) ctx.globalAlpha = 0.4;
          ctx.drawImage(textures['tree_canopy'], obj.data.x, obj.data.y, 140, 220); ctx.globalAlpha = 1.0; 
      } else if (obj.type === 'stone') ctx.drawImage(textures['stone'], obj.data.x - 10, obj.data.y - 10, TILE_SIZE*1.5, TILE_SIZE*1.5);
      else if (obj.type === 'big_rock') ctx.drawImage(textures['big_rock'], obj.data.x, obj.data.y, 100, 80);
      else if (obj.type === 'wall') ctx.drawImage(obj.data.tex, obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'door') {
          ctx.save(); const { x, y, angle, subType } = obj.data;
          // Убран минус перед углом для типов 'b' и 'r', чтобы они открывались в правильную сторону от игрока
          if (subType === 't') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'b') { ctx.translate(x, y + TILE_SIZE); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, -TILE_SIZE, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'l') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'r') { ctx.translate(x + TILE_SIZE, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, -TILE_SIZE, 0, TILE_SIZE, TILE_SIZE); }
          ctx.restore();
      } else if (obj.type === 'workbench') ctx.drawImage(textures['workbench'], obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'player') drawPlayer(ctx, obj.data.player, obj.data.isLocal, obj.data.isMoving, obj.data.isSprinting);
      else if (obj.type === 'ground_item') {
          const item = obj.data; ctx.save(); ctx.translate(item.x, item.y); ctx.rotate(item.rotation);
          const tex = (item.type === 'stick' || item.type === 'wood') ? textures['ground_twig'] : textures['ground_pebble'];
          if (tex) { const w = (item.type === 'stick' || item.type === 'wood') ? 32 : 16; ctx.drawImage(tex, -w/2, -w/2, w, w); }
          ctx.restore();
      }
  }

  // --- DAY/NIGHT OVERLAY ---
  ctx.restore(); // Выходим из мировых координат для полноэкранного фильтра
  ctx.save();
  const time = gameState.worldTime;
  let nightAlpha = 0;
  if (!gameState.useTestWorld && time > 14000 && time < 22000) { // В тестовом мире всегда день
      if (time < 18000) nightAlpha = (time - 14000) / 4000;
      else nightAlpha = 1 - (time - 18000) / 4000;
  }
  if (nightAlpha > 0) {
      const maxNight = 0.65;
      ctx.fillStyle = `rgba(10, 10, 40, ${nightAlpha * maxNight})`;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Легкое свечение вокруг игрока
      const gradient = ctx.createRadialGradient(logicalWidth/2, logicalHeight/2, 0, logicalWidth/2, logicalHeight/2, 200);
      gradient.addColorStop(0, 'rgba(255, 255, 200, 0.15)');
      gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.globalCompositeOperation = 'destination-out';
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.globalCompositeOperation = 'source-over';
  }
  ctx.restore();

  // Возвращаемся в мировые координаты для UI элементов над миром (прогресс добычи и т.д.)
  ctx.save();
  ctx.scale(dpr, dpr);
  ctx.translate(Math.floor(logicalWidth / 2), Math.floor(logicalHeight / 2));
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-Math.floor(camX), -Math.floor(camY));

  if (miningProgress > 0) {
      const worldX = targetX * TILE_SIZE + TILE_SIZE / 2, worldY = targetY * TILE_SIZE; 
      ctx.fillStyle = 'rgba(0,0,0,0.5)'; ctx.fillRect(worldX - 20, worldY - 15, 40, 6);
      ctx.fillStyle = '#4ade80'; ctx.fillRect(worldX - 20 + 1, worldY - 14, 38 * miningProgress, 4);
  }
  for (let i = floatingTexts.length - 1; i >= 0; i--) {
      const ft = floatingTexts[i]; ft.life--; ft.y -= 0.5; ctx.globalAlpha = ft.life / ft.maxLife;
      ctx.font = 'bold 16px sans-serif'; ctx.textAlign = 'center'; ctx.strokeStyle = 'black'; ctx.lineWidth = 3; ctx.strokeText(ft.text, ft.x, ft.y); ctx.fillStyle = ft.color; ctx.fillText(ft.text, ft.x, ft.y);
      ctx.globalAlpha = 1.0; if (ft.life <= 0) floatingTexts.splice(i, 1);
  }
  ctx.restore(); 
}

// index.tsx: Главная точка входа
import { Players, Player, Direction } from './types';
import { TILE_SIZE } from './constants';
import { initInput, inputState } from './input';

// Modules
import { gameState, setPlayers, setLocalPlayerId, getLocalPlayer } from './state';
import { initRenderer, renderGame, adjustZoom, getCameraZoom, addFloatingText, resetCamera } from './renderer';
import { generateAssets } from './assets';
import { initWorld, applyWorldUpdate, canMoveTo, isPositionInWater } from './world';
import { updateDoorPhysics } from './physics'; 
import { initInventory, syncInventoryWithServer, toggleInventory, handleHotbarKey, resetInventory, isInventoryOpen, getSelectedItem, cycleHotbar } from './inventory';
import { initUI, showGameScreen, updateOnlineCount, updateRoomList } from './ui';
import { initNetwork, emitMovement } from './network';
import { isChatOpen, toggleChat, addChatMessage } from './chat';
import { handleInteraction, currentMiningProgress, currentMiningTargetX, currentMiningTargetY, placementRotation, setPlacementRotation } from './interaction';
import { PLAYER_COLORS } from './assetHuman';

const canvas = document.getElementById('game-canvas') as HTMLCanvasElement;
const gameContainer = document.getElementById('game-container') as HTMLDivElement;

const hudEls = {
    hp: document.getElementById('bar-hp-fill'),
    hunger: document.getElementById('bar-hunger-fill'),
    mana: document.getElementById('bar-mana-fill'),
    energy: document.getElementById('bar-energy-fill'),
    xp: document.getElementById('bar-xp-fill'),
    level: document.getElementById('level-val'),
    textHp: document.getElementById('text-hp'),
    textHunger: document.getElementById('text-hunger'),
    textMana: document.getElementById('text-mana'),
    textEnergy: document.getElementById('text-energy')
};

const BASE_WALK_SPEED = 3;
const BASE_SPRINT_SPEED = 6;
let fps = 0;
let lastLoop = 0;
let isGameRunning = false;
const fpsEl = document.getElementById('fps-counter');
let lastRotateTime = 0;

document.addEventListener('DOMContentLoaded', () => {
    initRenderer(canvas);
    generateAssets();
    initInventory();

    // Сразу устанавливаем размеры канваса, чтобы избежать проблем с координатами
    resizeCanvas();

    const movement = initInput(canvas);

    initUI({ onStartOffline: startGameOffline });

    initNetwork({
        onConnect: (id) => setLocalPlayerId(id),
        onOnlineCount: updateOnlineCount,
        onRoomList: updateRoomList,
        onGameStart: (players, worldChanges, seed) => {
            gameState.isOffline = false;
            if (seed) gameState.worldSeed = seed;
            if (worldChanges) worldChanges.forEach(update => applyWorldUpdate(update));
            startGame(players, gameState.localPlayerId);
            addChatMessage("SYSTEM", `Welcome to Terra Wilds! Seed: ${gameState.worldSeed}`, "#fbbf24", true);
        },
        onState: (serverPlayers, serverTime) => {
            const me = getLocalPlayer();
            const serverMe = serverPlayers[gameState.localPlayerId];

            // Синхронизация времени с сервера
            if (typeof serverTime === 'number') {
                gameState.worldTime = serverTime;
            }

            if (me && serverMe) {
                if (serverMe.inventory) syncInventoryWithServer(serverMe.inventory);
                if (serverMe.stats) {
                    me.stats.hp = serverMe.stats.hp;
                    me.stats.maxHp = serverMe.stats.maxHp;
                    me.stats.hunger = serverMe.stats.hunger;
                    me.stats.xp = serverMe.stats.xp;
                    me.stats.level = serverMe.stats.level;
                    if (Math.abs(me.stats.energy - serverMe.stats.energy) > 5) me.stats.energy = serverMe.stats.energy;
                }
                const dist = Math.sqrt(Math.pow(me.x - serverMe.x, 2) + Math.pow(me.y - serverMe.y, 2));
                if (dist > 150) { 
                    me.x = serverMe.x; 
                    me.y = serverMe.y;
                    // Если произошла телепортация (первая синхронизация), сбрасываем камеру в renderer
                    resetCamera(me.x, me.y);
                }
                else serverPlayers[gameState.localPlayerId] = me;
            }
            setPlayers(serverPlayers);
        },
        onWorldUpdate: (update) => applyWorldUpdate(update),
        onError: (msg) => alert(`Ошибка: ${msg}`),
        onDebugLog: (msg) => console.error(msg),
        onChatMessage: (data) => addChatMessage(data.nickname, data.text, data.color)
    });

    window.addEventListener('resize', resizeCanvas);
    canvas.addEventListener('wheel', (e) => {
        if (!gameContainer.classList.contains('hidden')) { e.preventDefault(); adjustZoom(e.deltaY); }
    }, { passive: false });

    window.addEventListener('keydown', (e) => {
        const startScreen = document.getElementById('start-screen');
        if (startScreen && startScreen.classList.contains('hidden')) {
            if (!isChatOpen && (e.code === 'Enter' || e.code === 'KeyT')) { e.preventDefault(); toggleChat(true); return; }
            if (e.code === 'Escape') { if (isChatOpen) toggleChat(false); else if (isInventoryOpen) toggleInventory(); return; }
            if (isChatOpen) return;
            if (e.code === 'Tab') { e.preventDefault(); toggleInventory(); }
            if (e.code === 'KeyQ') cycleHotbar(-1);
            if (e.code === 'KeyE') cycleHotbar(1);
            if (e.key >= '1' && e.key <= '9') handleHotbarKey(parseInt(e.key) - 1);
        }
    });

    function resizeCanvas() { 
        const dpr = window.devicePixelRatio || 1;
        // Округляем до целых для избежания субпиксельных артефактов
        const w = Math.floor(window.innerWidth * dpr);
        const h = Math.floor(window.innerHeight * dpr);

        // Обновляем только если размеры изменились
        if (canvas.width !== w || canvas.height !== h) {
            canvas.width = w; 
            canvas.height = h;
            canvas.style.width = window.innerWidth + 'px'; 
            canvas.style.height = window.innerHeight + 'px';
            const ctx = canvas.getContext('2d');
            if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
        }
    }

    function startGame(initialPlayers: Players, playerId: string) {
        setPlayers(initialPlayers);
        setLocalPlayerId(playerId);
        resetInventory();
        const me = initialPlayers[playerId];
        if (me && me.inventory) syncInventoryWithServer(me.inventory);
        initWorld(me.x, me.y);
        showGameScreen();
        resizeCanvas();
        resetCamera(me.x, me.y); // Центрируем камеру на старте (включит snapFrames)
        if (fpsEl) fpsEl.classList.remove('hidden');

        // Запускаем цикл только если он еще не запущен
        if (!isGameRunning) {
            isGameRunning = true;
            gameLoop();
        }
    }

    function startGameOffline() {
        const pid = 'offline_hero';
        if (!gameState.worldSeed || gameState.worldSeed === 'terrawilds') gameState.worldSeed = Math.floor(Math.random() * 1999999999 - 999999999).toString();
        const player: Player = {
            id: pid, x: 0, y: 0, 
            color: PLAYER_COLORS[Math.floor(Math.random() * PLAYER_COLORS.length)], 
            nickname: "Explorer", direction: 'front',
            inventory: [], equipment: { head: null, body: null, legs: null },
            stats: { hp: 20, maxHp: 20, hunger: 20, maxHunger: 20, mana: 20, maxMana: 20, energy: 20, maxEnergy: 20, xp: 0, maxXp: 100, level: 1 }
        };
        startGame({ [pid]: player }, pid);
        if (gameState.useTestWorld) {
            const debugPanel = document.getElementById('debug-panel');
            if (debugPanel) debugPanel.style.display = 'block';
            addChatMessage("DEV", "ТЕСТОВЫЙ МИР: Бесконечные ресурсы и респавн включены.", "#60a5fa", true);
        } else {
            addChatMessage("AI", "Мир готов! Смена дня и ночи запущена. Загляни в дебаг-меню (/debug) для управления временем!", "#10b981");
        }
    }

    function gameLoop() {
        if (gameContainer.classList.contains('hidden')) {
            isGameRunning = false;
            return;
        }

        // Легковесная проверка изменения размера окна (например, на мобильных при скрытии адресной строки)
        const dpr = window.devicePixelRatio || 1;
        if (Math.abs(canvas.width - window.innerWidth * dpr) > 10) {
            resizeCanvas();
        }

        const now = performance.now();
        const delta = now - lastLoop;
        lastLoop = now;

        // Продвижение времени (только в офлайне, в онлайне берем с сервера)
        if (gameState.isOffline && !gameState.isTimePaused) {
            gameState.worldTime = (gameState.worldTime + 5) % 24000;
        }

        const me = getLocalPlayer();
        if (me) {
            if (movement.rotate && now - lastRotateTime > 200) { setPlacementRotation((placementRotation + 1) % 4); lastRotateTime = now; }
            handleInteraction(me);
            updateDoorPhysics(); 
            let canSprint = false; let currentSpeed = BASE_WALK_SPEED; let dx = 0, dy = 0; let newDir: Direction = me.direction;
            if (!isChatOpen) {
                if (me.stats) {
                    if (movement.sprint && me.stats.energy > 0) { canSprint = true; me.stats.energy -= 0.15; }
                    else if (!movement.sprint && me.stats.energy < me.stats.maxEnergy) me.stats.energy += 0.1;
                }
                currentSpeed = (canSprint ? BASE_SPRINT_SPEED : BASE_WALK_SPEED) * gameState.debug.speedMult;
                if (isPositionInWater(me.x, me.y)) currentSpeed *= 0.5;
                if (movement.up) { dy -= currentSpeed; newDir = 'back'; }
                if (movement.down) { dy += currentSpeed; newDir = 'front'; }
                if (movement.left) { dx -= currentSpeed; newDir = 'left'; }
                if (movement.right) { dx += currentSpeed; newDir = 'right'; }
            }
            if (dx !== 0 || dy !== 0) { 
                me.direction = newDir; (window as any).isLocalMoving = true; 
                if (dx !== 0 && canMoveTo(me.x + dx, me.y, 32, 32)) me.x += dx;
                if (dy !== 0 && canMoveTo(me.x, me.y + dy, 32, 32)) me.y += dy;
            } else (window as any).isLocalMoving = false;
            if (!gameState.isOffline) emitMovement({ x: me.x, y: me.y, direction: me.direction, sprint: canSprint });
            if (me.stats && hudEls.hp) {
                hudEls.hp.style.width = `${(me.stats.hp / me.stats.maxHp) * 100}%`;
                hudEls.hunger!.style.width = `${(me.stats.hunger / me.stats.maxHunger) * 100}%`;
                hudEls.mana!.style.width = `${(me.stats.mana / me.stats.maxMana) * 100}%`;
                hudEls.energy!.style.width = `${(me.stats.energy / me.stats.maxEnergy) * 100}%`;
                hudEls.xp!.style.width = `${(me.stats.xp / me.stats.maxXp) * 100}%`;
                hudEls.textHp!.textContent = String(Math.floor(me.stats.hp));
                hudEls.textHunger!.textContent = String(Math.floor(me.stats.hunger));
                hudEls.textEnergy!.textContent = String(Math.floor(me.stats.energy));
                hudEls.level!.textContent = String(me.stats.level);
            }
        }
        renderGame(currentMiningProgress, currentMiningTargetX, currentMiningTargetY, !isChatOpen && movement.sprint && me?.stats && me.stats.energy > 0);
        requestAnimationFrame(gameLoop);
    }
});

// renderer.ts: Отрисовка игрового мира и сущностей
import { TILE_SIZE } from './constants';
import { Player } from './types';
import { gameState } from './state';
import { textures, charSprites, AnimFrame } from './assets';
import { getTileData, isPositionInWater, canPlaceObject, getInteractionType } from './world';
import { getSelectedItem } from './inventory';
import { inputState } from './input';
import { placementRotation } from './interaction'; 

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;
export let cameraZoom = 1.5; 

let camX = 0;
let camY = 0;
let isCameraInitialized = false;
let loaderEl: HTMLElement | null = null;
let framesSinceStart = 0; // Счетчик кадров рендеринга
let isLoaderFading = false; // Флаг начала исчезновения загрузчика

interface FloatingText {
    x: number; y: number; text: string; life: number; maxLife: number; color: string;
}
const floatingTexts: FloatingText[] = [];

export function addFloatingText(x: number, y: number, text: string, color: string = '#ffffff') {
    floatingTexts.push({ x, y, text, life: 60, maxLife: 60, color });
}

export function getCameraZoom() { return cameraZoom; }

export function initRenderer(canvasEl: HTMLCanvasElement) {
    canvas = canvasEl; ctx = canvas.getContext('2d');
    if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
    loaderEl = document.getElementById('world-loader');
}

export function resetCamera(x: number, y: number) {
    camX = x;
    camY = y;
    isCameraInitialized = true;
    framesSinceStart = 0;
    isLoaderFading = false;

    // Показываем загрузчик при сбросе (новая игра)
    if (loaderEl) {
        loaderEl.classList.remove('hidden-loader');
        loaderEl.classList.remove('fade-out');
    }
}

export function adjustZoom(deltaY: number) {
    cameraZoom -= deltaY * 0.001;
    if (cameraZoom < 0.8) cameraZoom = 0.8;
    if (cameraZoom > 3.0) cameraZoom = 3.0;
}

function getAnimationFrame(isMoving: boolean, isSprinting: boolean): AnimFrame {
    if (!isMoving) return 0;
    const frameDuration = isSprinting ? 75 : 150;
    const now = Date.now();
    const cycle = Math.floor(now / frameDuration) % 4;
    return (cycle === 3) ? 2 : (cycle as AnimFrame);
}

export function drawCharacterPreview(ctxPreview: CanvasRenderingContext2D, player: Player) {
    const w = ctxPreview.canvas.width; const h = ctxPreview.canvas.height;
    ctxPreview.clearRect(0, 0, w, h); ctxPreview.save(); ctxPreview.translate(w/2, h/2); ctxPreview.scale(1.2, 1.2); ctxPreview.translate(-32, -42); 

    // Выбираем спрайт по цвету игрока
    const baseKey = `base_${player.color}`;
    const baseSprite = (charSprites[baseKey] && charSprites[baseKey][0]) ? charSprites[baseKey][0] : (charSprites['base_#FFFFFF'] ? charSprites['base_#FFFFFF'][0] : charSprites['base'][0]);

    if (baseSprite) ctxPreview.drawImage(baseSprite, 0, 0, 64, 84);

    if (player.equipment.legs && charSprites[player.equipment.legs]) ctxPreview.drawImage(charSprites[player.equipment.legs][0], 0, 0, 64, 84);
    if (player.equipment.body && charSprites[player.equipment.body]) ctxPreview.drawImage(charSprites[player.equipment.body][0], 0, 0, 64, 84);
    if (player.equipment.head && charSprites[player.equipment.head]) ctxPreview.drawImage(charSprites[player.equipment.head][0], 0, 0, 64, 84);
    ctxPreview.restore();
}

function drawPlayer(ctx: CanvasRenderingContext2D, player: Player, isLocal: boolean, isMoving: boolean, isSprinting: boolean) {
    const isInWater = isPositionInWater(player.x, player.y);
    const x = player.x; let y = player.y;
    if (isInWater) y += 5 + Math.sin(Date.now() / 400) * 2; 
    const frame = getAnimationFrame(isMoving, isSprinting);
    const dir = player.direction || 'front';
    const isFlipped = dir === 'right';
    ctx.save(); ctx.translate(x, y);
    if (!isLocal) {
        ctx.fillStyle = '#FFFFFF'; ctx.shadowColor = 'black'; ctx.shadowBlur = 4; ctx.font = 'bold 12px sans-serif'; ctx.textAlign = 'center'; ctx.fillText(player.nickname, 0, -55); ctx.shadowBlur = 0;
    }
    if (!isInWater) { ctx.fillStyle = 'rgba(0,0,0,0.25)'; ctx.beginPath(); ctx.ellipse(0, 12, 16, 6, 0, 0, Math.PI*2); ctx.fill(); }
    else {
        const ripple = (Math.sin(Date.now() / 500) + 1) / 2;
        ctx.strokeStyle = `rgba(255, 255, 255, ${0.4 - ripple * 0.2})`; ctx.lineWidth = 2; ctx.beginPath(); ctx.ellipse(0, 0, 12 + ripple * 4, 6 + ripple * 2, 0, 0, Math.PI*2); ctx.stroke();
    }
    if (isFlipped) ctx.scale(-1, 1);
    if (isInWater) { ctx.beginPath(); ctx.rect(-40, -100, 80, 100); ctx.clip(); }
    ctx.translate(-32, -60); 

    // Выбираем правильный спрайт базы на основе цвета игрока
    const baseKey = `base_${player.color}`;
    // Fallback: если цвет не найден (например, старый кеш), берем белый
    const baseSpriteSet = charSprites[baseKey] || charSprites['base_#FFFFFF'] || charSprites['base'];

    if (baseSpriteSet && baseSpriteSet[frame]) ctx.drawImage(baseSpriteSet[frame], 0, 0, 64, 84);

    if (player.equipment) {
        if (player.equipment.legs && charSprites[player.equipment.legs]) ctx.drawImage(charSprites[player.equipment.legs][frame], 0, 0, 64, 84);
        if (player.equipment.body && charSprites[player.equipment.body]) ctx.drawImage(charSprites[player.equipment.body][frame], 0, 0, 64, 84);
        if (player.equipment.head && charSprites[player.equipment.head]) ctx.drawImage(charSprites[player.equipment.head][frame], 0, 0, 64, 84);
    }
    if (isLocal) {
        const item = getSelectedItem();
        if (item) {
            ctx.font = '24px sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; 

            // Если персонаж развернут, нужно развернуть текст обратно,
            // но при этом скорректировать координату X, так как система координат смещена
            if (isFlipped) {
                ctx.scale(-1, 1);
                // В развернутой системе координат центр спрайта смещается
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, -32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            } else {
                ctx.shadowColor = 'rgba(0,0,0,0.5)'; ctx.shadowBlur = 10; 
                ctx.fillText(item.icon, 32, -15 + Math.sin(Date.now() / 300) * 3); 
                ctx.shadowBlur = 0;
            }
        }
    }
    ctx.restore();
}

interface RenderObject { y: number; type: string; data: any; }

function lerp(start: number, end: number, t: number) { return start * (1 - t) + end * t; }

export function renderGame(miningProgress: number = 0, targetX: number = 0, targetY: number = 0, isSprinting: boolean = false) {
  if (!ctx || !canvas) return;
  const me = gameState.players[gameState.localPlayerId];
  if (!me) return;

  framesSinceStart++;

  // --- ЛОГИКА КАМЕРЫ И ЗАГРУЗЧИКА ---

  const hasLoader = loaderEl && !loaderEl.classList.contains('hidden-loader') && !isLoaderFading;

  if (hasLoader) {
      // Пока виден загрузчик, камера ЖЕСТКО привязана к игроку
      camX = me.x;
      camY = me.y;
      isCameraInitialized = true;

      // Условие скрытия загрузчика:
      // 1. Прошло минимум 60 кадров (1 сек) для прогрузки чанков
      // 2. Координаты игрока не нулевые (получены от сервера)
      if (framesSinceStart > 60 && (Math.abs(me.x) > 1 || Math.abs(me.y) > 1 || framesSinceStart > 180)) {
          isLoaderFading = true;
          if (loaderEl) loaderEl.classList.add('fade-out');

          // Полностью убираем из DOM через секунду анимации
          setTimeout(() => {
              if (loaderEl) loaderEl.classList.add('hidden-loader');
          }, 1000);
      }
  } else {
      // Обычное поведение камеры (плавное слежение)
      const dist = Math.sqrt((camX - me.x)**2 + (camY - me.y)**2);

      // Защита от "нулевого бага" или телепорта: если камера слишком далеко, прыгаем
      if (dist > 400) { 
          camX = me.x; 
          camY = me.y; 
      } else {
          const lerpFactor = isSprinting ? 0.1 : 0.15; 
          camX = lerp(camX, me.x, lerpFactor); 
          camY = lerp(camY, me.y, lerpFactor);
      }
  }

  // Защита от NaN
  if (isNaN(camX)) camX = me.x;
  if (isNaN(camY)) camY = me.y;

  const dpr = window.devicePixelRatio || 1;

  // ФОН: Если тестовый мир - белый/серый, иначе зеленый
  ctx.fillStyle = gameState.useTestWorld ? '#e2e8f0' : '#4e8c33'; 
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  ctx.save();
  ctx.scale(dpr, dpr);
  // Используем размеры канваса для точного центрирования
  const logicalWidth = canvas.width / dpr; 
  const logicalHeight = canvas.height / dpr;

  ctx.translate(Math.floor(logicalWidth / 2), Math.floor(logicalHeight / 2));
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-Math.floor(camX), -Math.floor(camY)); // Округляем для четкости пикселей

  const viewW = logicalWidth / cameraZoom, viewH = logicalHeight / cameraZoom;
  const startTileX = Math.floor((camX - viewW/2) / TILE_SIZE) - 1;
  const endTileX = Math.floor((camX + viewW/2) / TILE_SIZE) + 2;
  const startTileY = Math.floor((camY - viewH/2) / TILE_SIZE) - 2; 
  const endTileY = Math.floor((camY + viewH/2) / TILE_SIZE) + 4;

  const renderList: RenderObject[] = [];

  for (let x = startTileX; x <= endTileX; x++) {
    for (let y = startTileY; y <= endTileY; y++) {
        const screenX = x * TILE_SIZE, screenY = y * TILE_SIZE;
        const tileData = getTileData(x, y);

        // РЕНДЕРИНГ ПОВЕРХНОСТИ
        if (tileData.terrain === 'water') {
            ctx.drawImage(textures['water'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            // --- ЛОГИКА БЕРЕГОВ (СКРУГЛЕНИЯ) ---
            const isN = getTileData(x, y - 1).terrain === 'grass';
            const isS = getTileData(x, y + 1).terrain === 'grass';
            const isW = getTileData(x - 1, y).terrain === 'grass';
            const isE = getTileData(x + 1, y).terrain === 'grass';

            if (isN && isW) ctx.drawImage(textures['mask_corner_tl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isN && isE) ctx.drawImage(textures['mask_corner_tr'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isW) ctx.drawImage(textures['mask_corner_bl'], screenX, screenY, TILE_SIZE, TILE_SIZE);
            if (isS && isE) ctx.drawImage(textures['mask_corner_br'], screenX, screenY, TILE_SIZE, TILE_SIZE);

            const waveHash = Math.sin(x * 12.9898 + y * 78.233) * 43758.5453;
            if ((waveHash - Math.floor(waveHash)) > 0.85) ctx.drawImage(textures['water_wave'], screenX, screenY + Math.sin(Date.now() / 500) * 2, TILE_SIZE, TILE_SIZE);
        } else if (!gameState.useTestWorld) {
            ctx.drawImage(textures['grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.floor === 'wood') ctx.drawImage(textures['floor_wood'], screenX, screenY, TILE_SIZE, TILE_SIZE);

        if (gameState.showDebugGrid || gameState.useTestWorld) {
            ctx.strokeStyle = gameState.useTestWorld ? 'rgba(0,0,0,0.05)' : 'rgba(255,255,255,0.1)'; 
            ctx.strokeRect(screenX, screenY, TILE_SIZE, TILE_SIZE);
        }

        if (tileData.object === 'tree') renderList.push({ y: screenY + 35, type: 'tree', data: { x: screenX - 50, y: screenY - 180 } });
        else if (tileData.object === 'stone') renderList.push({ y: screenY + 30, type: 'stone', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'big_rock') renderList.push({ y: screenY + 38, type: 'big_rock', data: { x: screenX - 30, y: screenY - 40 } });
        else if (tileData.object === 'workbench') renderList.push({ y: screenY + 30, type: 'workbench', data: { x: screenX, y: screenY } });
        else if (tileData.object === 'high_grass') ctx.drawImage(textures['high_grass'], screenX, screenY, TILE_SIZE, TILE_SIZE);
        else if (tileData.object.startsWith('wall_wood') || tileData.object.startsWith('door_wood')) {
             let sortY = screenY + TILE_SIZE; if (tileData.object.includes('_t')) sortY = screenY + 10;
             let angle = 0; if (tileData.object.startsWith('door_wood')) { const k = `${x},${y}`; if (gameState.doorStates[k]) angle = gameState.doorStates[k].angle; }
             renderList.push({ y: sortY, type: tileData.object.startsWith('door_wood') ? 'door' : 'wall', data: { x: screenX, y: screenY, tex: textures[tileData.object], angle, subType: tileData.object.split('_').pop() } });
        }
        tileData.items.forEach((item, i) => {
            const seed = x * 1000 + y + i * 50;
            renderList.push({ y: screenY + TILE_SIZE/2, type: 'ground_item', data: { x: screenX + TILE_SIZE/2 + Math.sin(seed)*10, y: screenY + TILE_SIZE/2 + Math.cos(seed)*10, type: item, rotation: Math.sin(seed*0.1)*Math.PI } });
        });
    }
  }
  for (const id in gameState.players) renderList.push({ y: gameState.players[id].y + 12, type: 'player', data: { player: gameState.players[id], isLocal: id === gameState.localPlayerId, isMoving: id === gameState.localPlayerId ? (window as any).isLocalMoving : false, isSprinting: id === gameState.localPlayerId ? isSprinting : false } });
  renderList.sort((a, b) => a.y - b.y);

  for (const obj of renderList) {
      if (obj.type === 'tree') {
          const dist = Math.sqrt((me.x - (obj.data.x + 70))**2 + (me.y - (obj.data.y + 110))**2);
          ctx.drawImage(textures['tree_trunk'], obj.data.x, obj.data.y, 140, 220);
          if (dist < 220 && me.y < obj.y) ctx.globalAlpha = 0.4;
          ctx.drawImage(textures['tree_canopy'], obj.data.x, obj.data.y, 140, 220); ctx.globalAlpha = 1.0; 
      } else if (obj.type === 'stone') ctx.drawImage(textures['stone'], obj.data.x - 10, obj.data.y - 10, TILE_SIZE*1.5, TILE_SIZE*1.5);
      else if (obj.type === 'big_rock') ctx.drawImage(textures['big_rock'], obj.data.x, obj.data.y, 100, 80);
      else if (obj.type === 'wall') ctx.drawImage(obj.data.tex, obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'door') {
          ctx.save(); const { x, y, angle, subType } = obj.data;
          // Убран минус перед углом для типов 'b' и 'r', чтобы они открывались в правильную сторону от игрока
          if (subType === 't') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'b') { ctx.translate(x, y + TILE_SIZE); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, -TILE_SIZE, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'l') { ctx.translate(x, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, 0, 0, TILE_SIZE, TILE_SIZE); }
          else if (subType === 'r') { ctx.translate(x + TILE_SIZE, y); ctx.rotate(angle); ctx.drawImage(obj.data.tex, -TILE_SIZE, 0, TILE_SIZE, TILE_SIZE); }
          ctx.restore();
      } else if (obj.type === 'workbench') ctx.drawImage(textures['workbench'], obj.data.x, obj.data.y, TILE_SIZE, TILE_SIZE);
      else if (obj.type === 'player') drawPlayer(ctx, obj.data.player, obj.data.isLocal, obj.data.isMoving, obj.data.isSprinting);
      else if (obj.type === 'ground_item') {
          const item = obj.data; ctx.save(); ctx.translate(item.x, item.y); ctx.rotate(item.rotation);
          const tex = (item.type === 'stick' || item.type === 'wood') ? textures['ground_twig'] : textures['ground_pebble'];
          if (tex) { const w = (item.type === 'stick' || item.type === 'wood') ? 32 : 16; ctx.drawImage(tex, -w/2, -w/2, w, w); }
          ctx.restore();
      }
  }

  // --- DAY/NIGHT OVERLAY ---
  ctx.restore(); // Выходим из мировых координат для полноэкранного фильтра
  ctx.save();
  const time = gameState.worldTime;
  let nightAlpha = 0;
  if (!gameState.useTestWorld && time > 14000 && time < 22000) { // В тестовом мире всегда день
      if (time < 18000) nightAlpha = (time - 14000) / 4000;
      else nightAlpha = 1 - (time - 18000) / 4000;
  }
  if (nightAlpha > 0) {
      const maxNight = 0.65;
      ctx.fillStyle = `rgba(10, 10, 40, ${nightAlpha * maxNight})`;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Легкое свечение вокруг игрока
      const gradient = ctx.createRadialGradient(logicalWidth/2, logicalHeight/2, 0, logicalWidth/2, logicalHeight/2, 200);
      gradient.addColorStop(0, 'rgba(255, 255, 200, 0.15)');
      gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.globalCompositeOperation = 'destination-out';
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.globalCompositeOperation = 'source-over';
  }
  ctx.restore();

  // Возвращаемся в мировые координаты для UI элементов над миром (прогресс добычи и т.д.)
  ctx.save();
  ctx.scale(dpr, dpr);
  ctx.translate(Math.floor(logicalWidth / 2), Math.floor(logicalHeight / 2));
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-Math.floor(camX), -Math.floor(camY));

  if (miningProgress > 0) {
      const worldX = targetX * TILE_SIZE + TILE_SIZE / 2, worldY = targetY * TILE_SIZE; 
      ctx.fillStyle = 'rgba(0,0,0,0.5)'; ctx.fillRect(worldX - 20, worldY - 15, 40, 6);
      ctx.fillStyle = '#4ade80'; ctx.fillRect(worldX - 20 + 1, worldY - 14, 38 * miningProgress, 4);
  }
  for (let i = floatingTexts.length - 1; i >= 0; i--) {
      const ft = floatingTexts[i]; ft.life--; ft.y -= 0.5; ctx.globalAlpha = ft.life / ft.maxLife;
      ctx.font = 'bold 16px sans-serif'; ctx.textAlign = 'center'; ctx.strokeStyle = 'black'; ctx.lineWidth = 3; ctx.strokeText(ft.text, ft.x, ft.y); ctx.fillStyle = ft.color; ctx.fillText(ft.text, ft.x, ft.y);
      ctx.globalAlpha = 1.0; if (ft.life <= 0) floatingTexts.splice(i, 1);
  }
  ctx.restore(); 
}

// index.tsx: Главная точка входа
import { Players, Player, Direction } from './types';
import { TILE_SIZE } from './constants';
import { initInput, inputState } from './input';

// Modules
import { gameState, setPlayers, setLocalPlayerId, getLocalPlayer } from './state';
import { initRenderer, renderGame, adjustZoom, getCameraZoom, addFloatingText, resetCamera } from './renderer';
import { generateAssets } from './assets';
import { initWorld, applyWorldUpdate, canMoveTo, isPositionInWater } from './world';
import { updateDoorPhysics } from './physics'; 
import { initInventory, syncInventoryWithServer, toggleInventory, handleHotbarKey, resetInventory, isInventoryOpen, getSelectedItem, cycleHotbar } from './inventory';
import { initUI, showGameScreen, updateOnlineCount, updateRoomList } from './ui';
import { initNetwork, emitMovement } from './network';
import { isChatOpen, toggleChat, addChatMessage } from './chat';
import { handleInteraction, currentMiningProgress, currentMiningTargetX, currentMiningTargetY, placementRotation, setPlacementRotation } from './interaction';
import { PLAYER_COLORS } from './assetHuman';

const canvas = document.getElementById('game-canvas') as HTMLCanvasElement;
const gameContainer = document.getElementById('game-container') as HTMLDivElement;

const hudEls = {
    hp: document.getElementById('bar-hp-fill'),
    hunger: document.getElementById('bar-hunger-fill'),
    mana: document.getElementById('bar-mana-fill'),
    energy: document.getElementById('bar-energy-fill'),
    xp: document.getElementById('bar-xp-fill'),
    level: document.getElementById('level-val'),
    textHp: document.getElementById('text-hp'),
    textHunger: document.getElementById('text-hunger'),
    textMana: document.getElementById('text-mana'),
    textEnergy: document.getElementById('text-energy')
};

const BASE_WALK_SPEED = 3;
const BASE_SPRINT_SPEED = 6;
let fps = 0;
let lastLoop = 0;
let isGameRunning = false;
const fpsEl = document.getElementById('fps-counter');
let lastRotateTime = 0;

document.addEventListener('DOMContentLoaded', () => {
    initRenderer(canvas);
    generateAssets();
    initInventory();

    // Сразу устанавливаем размеры канваса, чтобы избежать проблем с координатами
    resizeCanvas();

    const movement = initInput(canvas);

    initUI({ onStartOffline: startGameOffline });

    initNetwork({
        onConnect: (id) => setLocalPlayerId(id),
        onOnlineCount: updateOnlineCount,
        onRoomList: updateRoomList,
        onGameStart: (players, worldChanges, seed) => {
            gameState.isOffline = false;
            if (seed) gameState.worldSeed = seed;
            if (worldChanges) worldChanges.forEach(update => applyWorldUpdate(update));
            startGame(players, gameState.localPlayerId);
            addChatMessage("SYSTEM", `Welcome to Terra Wilds! Seed: ${gameState.worldSeed}`, "#fbbf24", true);
        },
        onState: (serverPlayers, serverTime) => {
            const me = getLocalPlayer();
            const serverMe = serverPlayers[gameState.localPlayerId];

            // Синхронизация времени с сервера
            if (typeof serverTime === 'number') {
                gameState.worldTime = serverTime;
            }

            if (me && serverMe) {
                if (serverMe.inventory) syncInventoryWithServer(serverMe.inventory);
                if (serverMe.stats) {
                    me.stats.hp = serverMe.stats.hp;
                    me.stats.maxHp = serverMe.stats.maxHp;
                    me.stats.hunger = serverMe.stats.hunger;
                    me.stats.xp = serverMe.stats.xp;
                    me.stats.level = serverMe.stats.level;
                    if (Math.abs(me.stats.energy - serverMe.stats.energy) > 5) me.stats.energy = serverMe.stats.energy;
                }
                const dist = Math.sqrt(Math.pow(me.x - serverMe.x, 2) + Math.pow(me.y - serverMe.y, 2));
                if (dist > 150) { 
                    me.x = serverMe.x; 
                    me.y = serverMe.y;
                }
                else serverPlayers[gameState.localPlayerId] = me;
            }
            setPlayers(serverPlayers);
        },
        onWorldUpdate: (update) => applyWorldUpdate(update),
        onError: (msg) => alert(`Ошибка: ${msg}`),
        onDebugLog: (msg) => console.error(msg),
        onChatMessage: (data) => addChatMessage(data.nickname, data.text, data.color)
    });

    window.addEventListener('resize', resizeCanvas);
    canvas.addEventListener('wheel', (e) => {
        if (!gameContainer.classList.contains('hidden')) { e.preventDefault(); adjustZoom(e.deltaY); }
    }, { passive: false });

    window.addEventListener('keydown', (e) => {
        const startScreen = document.getElementById('start-screen');
        if (startScreen && startScreen.classList.contains('hidden')) {
            if (!isChatOpen && (e.code === 'Enter' || e.code === 'KeyT')) { e.preventDefault(); toggleChat(true); return; }
            if (e.code === 'Escape') { if (isChatOpen) toggleChat(false); else if (isInventoryOpen) toggleInventory(); return; }
            if (isChatOpen) return;
            if (e.code === 'Tab') { e.preventDefault(); toggleInventory(); }
            if (e.code === 'KeyQ') cycleHotbar(-1);
            if (e.code === 'KeyE') cycleHotbar(1);
            if (e.key >= '1' && e.key <= '9') handleHotbarKey(parseInt(e.key) - 1);
        }
    });

    function resizeCanvas() { 
        const dpr = window.devicePixelRatio || 1;
        // Округляем до целых для избежания субпиксельных артефактов
        const w = Math.floor(window.innerWidth * dpr);
        const h = Math.floor(window.innerHeight * dpr);

        // Обновляем только если размеры изменились
        if (canvas.width !== w || canvas.height !== h) {
            canvas.width = w; 
            canvas.height = h;
            canvas.style.width = window.innerWidth + 'px'; 
            canvas.style.height = window.innerHeight + 'px';
            const ctx = canvas.getContext('2d');
            if (ctx) { ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high'; }
        }
    }

    function startGame(initialPlayers: Players, playerId: string) {
        setPlayers(initialPlayers);
        setLocalPlayerId(playerId);
        resetInventory();
        const me = initialPlayers[playerId];
        if (me && me.inventory) syncInventoryWithServer(me.inventory);
        initWorld(me.x, me.y);
        showGameScreen();
        resizeCanvas();
        resetCamera(me.x, me.y); // Этот вызов сбросит камеру и ПОКАЖЕТ ЗАГРУЗЧИК
        if (fpsEl) fpsEl.classList.remove('hidden');

        // Запускаем цикл только если он еще не запущен
        if (!isGameRunning) {
            isGameRunning = true;
            gameLoop();
        }
    }

    function startGameOffline() {
        const pid = 'offline_hero';
        if (!gameState.worldSeed || gameState.worldSeed === 'terrawilds') gameState.worldSeed = Math.floor(Math.random() * 1999999999 - 999999999).toString();
        const player: Player = {
            id: pid, x: 0, y: 0, 
            color: PLAYER_COLORS[Math.floor(Math.random() * PLAYER_COLORS.length)], 
            nickname: "Explorer", direction: 'front',
            inventory: [], equipment: { head: null, body: null, legs: null },
            stats: { hp: 20, maxHp: 20, hunger: 20, maxHunger: 20, mana: 20, maxMana: 20, energy: 20, maxEnergy: 20, xp: 0, maxXp: 100, level: 1 }
        };
        startGame({ [pid]: player }, pid);
        if (gameState.useTestWorld) {
            const debugPanel = document.getElementById('debug-panel');
            if (debugPanel) debugPanel.style.display = 'block';
            addChatMessage("DEV", "ТЕСТОВЫЙ МИР: Бесконечные ресурсы и респавн включены.", "#60a5fa", true);
        } else {
            addChatMessage("AI", "Мир готов! Смена дня и ночи запущена. Загляни в дебаг-меню (/debug) для управления временем!", "#10b981");
        }
    }

    function gameLoop() {
        if (gameContainer.classList.contains('hidden')) {
            isGameRunning = false;
            return;
        }

        // Легковесная проверка изменения размера окна (например, на мобильных при скрытии адресной строки)
        const dpr = window.devicePixelRatio || 1;
        if (Math.abs(canvas.width - window.innerWidth * dpr) > 10) {
            resizeCanvas();
        }

        const now = performance.now();
        const delta = now - lastLoop;
        lastLoop = now;

        // Продвижение времени (только в офлайне, в онлайне берем с сервера)
        if (gameState.isOffline && !gameState.isTimePaused) {
            gameState.worldTime = (gameState.worldTime + 5) % 24000;
        }

        const me = getLocalPlayer();
        if (me) {
            if (movement.rotate && now - lastRotateTime > 200) { setPlacementRotation((placementRotation + 1) % 4); lastRotateTime = now; }
            handleInteraction(me);
            updateDoorPhysics(); 
            let canSprint = false; let currentSpeed = BASE_WALK_SPEED; let dx = 0, dy = 0; let newDir: Direction = me.direction;
            if (!isChatOpen) {
                if (me.stats) {
                    if (movement.sprint && me.stats.energy > 0) { canSprint = true; me.stats.energy -= 0.15; }
                    else if (!movement.sprint && me.stats.energy < me.stats.maxEnergy) me.stats.energy += 0.1;
                }
                currentSpeed = (canSprint ? BASE_SPRINT_SPEED : BASE_WALK_SPEED) * gameState.debug.speedMult;
                if (isPositionInWater(me.x, me.y)) currentSpeed *= 0.5;
                if (movement.up) { dy -= currentSpeed; newDir = 'back'; }
                if (movement.down) { dy += currentSpeed; newDir = 'front'; }
                if (movement.left) { dx -= currentSpeed; newDir = 'left'; }
                if (movement.right) { dx += currentSpeed; newDir = 'right'; }
            }
            if (dx !== 0 || dy !== 0) { 
                me.direction = newDir; (window as any).isLocalMoving = true; 
                if (dx !== 0 && canMoveTo(me.x + dx, me.y, 32, 32)) me.x += dx;
                if (dy !== 0 && canMoveTo(me.x, me.y + dy, 32, 32)) me.y += dy;
            } else (window as any).isLocalMoving = false;
            if (!gameState.isOffline) emitMovement({ x: me.x, y: me.y, direction: me.direction, sprint: canSprint });
            if (me.stats && hudEls.hp) {
                hudEls.hp.style.width = `${(me.stats.hp / me.stats.maxHp) * 100}%`;
                hudEls.hunger!.style.width = `${(me.stats.hunger / me.stats.maxHunger) * 100}%`;
                hudEls.mana!.style.width = `${(me.stats.mana / me.stats.maxMana) * 100}%`;
                hudEls.energy!.style.width = `${(me.stats.energy / me.stats.maxEnergy) * 100}%`;
                hudEls.xp!.style.width = `${(me.stats.xp / me.stats.maxXp) * 100}%`;
                hudEls.textHp!.textContent = String(Math.floor(me.stats.hp));
                hudEls.textHunger!.textContent = String(Math.floor(me.stats.hunger));
                hudEls.textEnergy!.textContent = String(Math.floor(me.stats.energy));
                hudEls.level!.textContent = String(me.stats.level);
            }
        }
        renderGame(currentMiningProgress, currentMiningTargetX, currentMiningTargetY, !isChatOpen && movement.sprint && me?.stats && me.stats.energy > 0);
        requestAnimationFrame(gameLoop);
    }
});
